     1→import { NextResponse } from "next/server";
     2→import { z } from "zod";
     3→import crypto from "crypto";
     4→import { db } from "@/lib/db";
     5→import { rateLimit, requestIp } from "@/lib/rate-limit";
     6→
     7→export const runtime = "nodejs";
     8→
     9→const Schema = z.object({
    10→  method: z.enum(["email", "phone"]),
    11→  value: z.string().min(1),
    12→});
    13→
    14→async function sendResetSMS(phone: string, link: string) {
    15→  const sid   = process.env.TWILIO_ACCOUNT_SID;
    16→  const token = process.env.TWILIO_AUTH_TOKEN;
    17→  const from  = process.env.TWILIO_FROM;
    18→  if (!sid || !token || !from) {
    19→    console.log("[DEV] SMS reset link for", phone, "→", link);
    20→    return;
    21→  }
    22→  const twilio = (await import("twilio")).default;
    23→  const client = twilio(sid, token);
    24→  await client.messages.create({
    25→    to: phone,
    26→    from,
    27→    body: `West Coast Marine password reset: ${link}`,
    28→  });
    29→}
    30→
    31→async function sendResetEmail(email: string, link: string) {
    32→  const host = process.env.SMTP_HOST;
    33→  const user = process.env.SMTP_USER;
    34→  const pass = process.env.SMTP_PASS;
    35→  if (!host || !user || !pass) {
    36→    console.log("[DEV] Email reset link for", email, "→", link);
    37→    return;
    38→  }
    39→  const nodemailer = (await import("nodemailer")).default;
    40→  const transport = nodemailer.createTransport({ host, port: 587, auth: { user, pass } });
    41→  await transport.sendMail({
    42→    from: `"West Coast Marine" <${user}>`,
    43→    to: email,
    44→    subject: "Reset your password",
    45→    text: `Click to reset your West Coast Marine password:\n\n${link}\n\nLink expires in 1 hour.`,
    46→    html: `<p>Click to reset your West Coast Marine password:</p><p><a href="${link}">${link}</a></p><p>Link expires in 1 hour.</p>`,
    47→  });
    48→}
    49→
    50→export async function POST(req: Request) {
    51→  // Rate limit: 5 attempts per hour per IP
    52→  const ip = requestIp(req);
    53→  const rl = rateLimit(`forgot-pw:${ip}`, 5, 60 * 60 * 1000);
    54→  if (!rl.allowed) {
    55→    return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 });
    56→  }
    57→
    58→  const body   = await req.json().catch(() => null);
    59→  const parsed = Schema.safeParse(body);
    60→  if (!parsed.success) return NextResponse.json({ error: "Invalid request" }, { status: 400 });
    61→
    62→  const { method, value } = parsed.data;
    63→  const normalised = value.trim().toLowerCase();
    64→
    65→  let user: { id: string; email: string; phone: string | null } | null = null;
    66→  if (method === "email") {
    67→    user = await db.user.findUnique({ where: { email: normalised }, select: { id: true, email: true, phone: true } });
    68→  } else {
    69→    user = await db.user.findFirst({ where: { phone: value.trim() }, select: { id: true, email: true, phone: true } });
    70→  }
    71→
    72→  // Always return 200 so we don't leak whether the account exists
    73→  if (!user) return NextResponse.json({ ok: true });
    74→
    75→  // Invalidate old tokens for this user
    76→  await db.passwordReset.updateMany({ where: { userId: user.id, used: false }, data: { used: true } });
    77→
    78→  const token     = crypto.randomBytes(32).toString("hex");
    79→  const expiresAt = new Date(Date.now() + 60 * 60 * 1000); // 1 hour
    80→  await db.passwordReset.create({ data: { userId: user.id, token, method, expiresAt } });
    81→
    82→  const baseUrl = process.env.NEXT_PUBLIC_BASE_URL ?? "https://splendorous-pony-31739a.netlify.app";
    83→  const link    = `${baseUrl}/reset-password?token=${token}`;
    84→
    85→  if (method === "email") {
    86→    await sendResetEmail(user.email, link);
    87→  } else {
    88→    await sendResetSMS(user.phone ?? value.trim(), link);
    89→  }
    90→
    91→  return NextResponse.json({ ok: true });
    92→}
    93→

