     1→import { NextResponse } from "next/server";
     2→import { z } from "zod";
     3→import bcrypt from "bcryptjs";
     4→import { db } from "@/lib/db";
     5→import { rateLimit, requestIp } from "@/lib/rate-limit";
     6→
     7→export const runtime = "nodejs";
     8→
     9→const Schema = z.object({
    10→  token:    z.string().min(1),
    11→  password: z.string().min(8),
    12→});
    13→
    14→export async function POST(req: Request) {
    15→  // Rate limit: 10 attempts per hour per IP (prevent token brute-force)
    16→  const ip = requestIp(req);
    17→  const rl = rateLimit(`reset-pw:${ip}`, 10, 60 * 60 * 1000);
    18→  if (!rl.allowed) {
    19→    return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 });
    20→  }
    21→
    22→  const body   = await req.json().catch(() => null);
    23→  const parsed = Schema.safeParse(body);
    24→  if (!parsed.success) return NextResponse.json({ error: "Invalid request" }, { status: 400 });
    25→
    26→  const { token, password } = parsed.data;
    27→
    28→  const record = await db.passwordReset.findUnique({ where: { token } });
    29→  if (!record || record.used || record.expiresAt < new Date()) {
    30→    return NextResponse.json({ error: "Reset link is invalid or has expired." }, { status: 400 });
    31→  }
    32→
    33→  const hash = await bcrypt.hash(password, 12);
    34→  await db.$transaction([
    35→    db.user.update({ where: { id: record.userId }, data: { passwordHash: hash } }),
    36→    db.passwordReset.update({ where: { id: record.id }, data: { used: true } }),
    37→  ]);
    38→
    39→  return NextResponse.json({ ok: true });
    40→}
    41→

