    12→function beep() {
    13→  try {
    14→    const w = window as unknown as {
    15→      AudioContext?: typeof AudioContext;
    16→      webkitAudioContext?: typeof AudioContext;
    17→    };
    18→    const AudioCtx = w.AudioContext ?? w.webkitAudioContext;
    19→    if (!AudioCtx) return;
    20→    const ctx = new AudioCtx();
    21→    const o = ctx.createOscillator();
    22→    const g = ctx.createGain();
    23→    o.type = "sine";
    24→    o.frequency.value = 880;
    25→    g.gain.value = 0.05;
    26→    o.connect(g);
    27→    g.connect(ctx.destination);
    28→    o.start();
    29→    setTimeout(() => {
    30→      o.stop();
    31→      ctx.close();
    32→    }, 140);
    33→  } catch {
    34→    // ignore
    35→  }
    36→}
