    38→export function TractorClient() {
    39→  const [active, setActive] = React.useState<QueueType>("LAUNCH");
    40→  const [launchData, setLaunchData] = React.useState<QueueResponseAdminDTO | null>(null);
    41→  const [retrievalData, setRetrievalData] = React.useState<QueueResponseAdminDTO | null>(null);
    42→  const [loading, setLoading] = React.useState(true);
    43→  const [error, setError] = React.useState<string | null>(null);
    44→
    45→  const prevCounts = React.useRef<{ launch: number; retrieval: number }>({ launch: 0, retrieval: 0 });
    46→
    47→  const loadAll = React.useCallback(async ({ allowBeep }: { allowBeep: boolean }) => {
    48→    setError(null);
    49→    setLoading(true);
    50→    try {
    51→      const fetchQueue = async (type: QueueType) => {
    52→        const res = await fetch(`/api/queues/${type}`, { cache: "no-store" });
    53→        if (!res.ok) throw new Error("Failed to load");
    54→        return (await res.json()) as QueueResponseAdminDTO;
    55→      };
    56→
    57→      const [l, r] = await Promise.all([fetchQueue("LAUNCH"), fetchQueue("RETRIEVAL")]);
    58→      const lCount = l.pending.length;
    59→      const rCount = r.pending.length;
    60→
    61→      if (allowBeep) {
    62→        if (lCount > prevCounts.current.launch || rCount > prevCounts.current.retrieval) beep();
    63→      }
    64→
    65→      prevCounts.current = { launch: lCount, retrieval: rCount };
    66→      setLaunchData(l);
    67→      setRetrievalData(r);
    68→    } catch {
    69→      setError("Failed to load queues");
    70→    } finally {
    71→      setLoading(false);
    72→    }
    73→  }, []);
    74→
    75→  React.useEffect(() => {
    76→    loadAll({ allowBeep: false });
    77→    let activeFlag = true;
    78→    (async () => {
    79→      const socket = await getSocket();
    80→      if (!activeFlag) return;
    81→      socket.emit("queues:subscribe", {});
    82→      const onUpdated = () => loadAll({ allowBeep: true });
    83→      socket.on("queues:updated", onUpdated);
    84→      return () => socket.off("queues:updated", onUpdated);
    85→    })();
    86→    return () => {
    87→      activeFlag = false;
    88→    };
    89→  }, [loadAll]);
    90→
    91→  const data = active === "LAUNCH" ? launchData : retrievalData;
    92→  const pending = data?.pending ?? [];
