"use client";

import * as React from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { getSocket } from "@/lib/socketClient";
import { triggerBoatAnimation } from "@/components/boat-animation";
import { playAdminAlert, playCustomerNotification } from "@/lib/queueSounds";
import type { QueueResponseAdminDTO, QueueResponseCustomerDTO } from "@/lib/apiTypes";

type QueueType = "LAUNCH" | "RETRIEVAL";

export function CombinedQueueClient({ isAdmin }: { isAdmin: boolean }) {
  type QueueData = QueueResponseAdminDTO | QueueResponseCustomerDTO;
  const [launchData, setLaunchData] = React.useState<QueueData | null>(null);
  const [retrievalData, setRetrievalData] = React.useState<QueueData | null>(null);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string | null>(null);
  const [actionPendingId, setActionPendingId] = React.useState<string | null>(null);

  const load = React.useCallback(async () => {
    setError(null);
    setLoading(true);
    try {
      const [launchRes, retrievalRes] = await Promise.all([
        fetch(`/api/queues/LAUNCH`, { cache: "no-store" }),
        fetch(`/api/queues/RETRIEVAL`, { cache: "no-store" }),
      ]);

      if (!launchRes.ok || !retrievalRes.ok) {
        setError("Failed to load queues");
        setLoading(false);
        return;
      }

      const [launch, retrieval] = await Promise.all([launchRes.json(), retrievalRes.json()]);
      setLaunchData(launch);
      setRetrievalData(retrieval);
    } catch {
      setError("Failed to load queues");
    } finally {
      setLoading(false);
    }
  }, []);

  async function markCompleted(id: string, type: QueueType) {
    if (!isAdmin) return;
    setActionPendingId(id);
    try {
      await fetch(`/api/admin/bookings/${id}`, {
        method: "PATCH",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ action: "MARK_COMPLETED" }),
      });
      triggerBoatAnimation(type === "LAUNCH" ? "launch" : "retrieval");
      await load();
    } finally {
      setActionPendingId(null);
    }
  }

  React.useEffect(() => {
    load();
    let active = true;
    const refreshInterval = setInterval(() => { if (active) load(); }, 3 * 60 * 1000);
    (async () => {
      const socket = await getSocket();
      if (!active) return;
      socket.emit("queues:subscribe", {});
      const onUpdated = () => {
        load();
        if (isAdmin) playAdminAlert();
        else playCustomerNotification();
      };
      socket.on("queues:updated", onUpdated);
      return () => {
        socket.off("queues:updated", onUpdated);
      };
    })();
    return () => {
      active = false;
      clearInterval(refreshInterval);
    };
  }, [load]);

  const renderQueueSection = (type: QueueType, data: QueueData | null) => {
    const pending = data?.pending ?? [];
    const completed = data?.completed ?? [];
    const title = type === "LAUNCH" ? "Launch Queue" : "Retrieval Queue";
    const buttonLabel = type === "LAUNCH" ? "Launched" : "Retrieved";

    return (
      <div className="space-y-4">
        <h2 className={`text-lg font-semibold ${type === "LAUNCH" ? "text-green-700" : "text-red-700"}`}>
          {title} ({pending.length + completed.length})
        </h2>

        {error && type === "LAUNCH" ? (
          <div className="rounded-xl bg-red-50 p-4 text-sm text-red-700">{error}</div>
        ) : null}

        <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
          {/* Pending */}
          <Card>
            <CardHeader>
              <CardTitle>
                Pending ({pending.length})
                {isAdmin ? <span className="ml-2 text-xs font-medium text-zinc-500">(staff view)</span> : null}
              </CardTitle>
            </CardHeader>
            <CardContent>
              {loading ? (
                <div className="text-sm text-zinc-600">Loading…</div>
              ) : pending.length === 0 ? (
                <div className="text-sm text-zinc-600">No pending requests.</div>
              ) : (
                <div className="space-y-2">
                  {pending.map((b, i) => {
                    const adminB = isAdmin ? (b as QueueResponseAdminDTO["pending"][number]) : null;
                    const custB = !isAdmin ? (b as QueueResponseCustomerDTO["pending"][number]) : null;
                    return (
                      <div
                        key={b.id}
                        className="flex items-start justify-between gap-2 rounded-lg border border-zinc-100 bg-zinc-50 p-3"
                      >
                        <div className="flex items-start gap-3 min-w-0">
                          <span className={`mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full text-xs font-bold text-white ${type === "LAUNCH" ? "bg-green-700" : "bg-red-700"}`}>
                            {i + 1}
                          </span>
                          <div className="min-w-0 space-y-0.5">
                            <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                              <span className="font-semibold text-zinc-900 text-sm">
                                {adminB ? adminB.vessel.boatName : custB?.vessel.boatName}
                              </span>
                              {b.vessel?.yardNumber ? (
                                <span className="text-xs font-medium text-zinc-500">Yard #{b.vessel.yardNumber}</span>
                              ) : null}
                              {b.vessel?.owner?.username ? (
                                <span className="rounded-full bg-sky-100 px-2 py-0.5 text-xs font-bold text-sky-700">@{b.vessel.owner.username}</span>
                              ) : null}
                            </div>
                            <div className="flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-zinc-600">
                              {adminB ? (
                                <>
                                  {adminB.vessel.boatType ? <span>{adminB.vessel.boatType}</span> : null}
                                  {adminB.vessel.boatNumber ? <span>#{adminB.vessel.boatNumber}</span> : null}
                                  <span className="font-medium text-zinc-700">{adminB.vessel.owner.name}</span>
                                  {adminB.vessel.owner.phone ? (
                                    <a href={`tel:${adminB.vessel.owner.phone}`} className="text-sky-600 hover:underline">
                                      {adminB.vessel.owner.phone}
                                    </a>
                                  ) : null}
                                </>
                              ) : (
                                <>
                                  {custB?.vessel.boatType ? <span>{custB.vessel.boatType}</span> : null}
                                  <span className="font-medium text-zinc-700">{custB?.vessel.owner.name}</span>
                                </>
                              )}
                            </div>
                            <div className="flex flex-wrap items-center gap-2 mt-1">
                              {b.stayingOnMooring ? (
                                <span className="inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-700">
                                  Staying on mooring
                                </span>
                              ) : null}
                              <span className="text-xs text-zinc-400">
                                {b.requestedAt ? new Date(b.requestedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}
                              </span>
                            </div>
                          </div>
                        </div>
                        {isAdmin ? (
                          <Button
                            size="sm"
                            variant="secondary"
                            className="shrink-0 text-xs"
                            disabled={actionPendingId === b.id}
                            onClick={() => markCompleted(b.id, type)}
                          >
                            {actionPendingId === b.id ? "…" : buttonLabel}
                          </Button>
                        ) : null}
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Completed */}
          <Card>
            <CardHeader>
              <CardTitle>Completed ({completed.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {loading ? (
                <div className="text-sm text-zinc-600">Loading…</div>
              ) : completed.length === 0 ? (
                <div className="text-sm text-zinc-600">None completed yet.</div>
              ) : (
                <div className="space-y-2">
                  {completed.map((b) => {
                    const adminB = isAdmin ? (b as QueueResponseAdminDTO["completed"][number]) : null;
                    const custB = !isAdmin ? (b as QueueResponseCustomerDTO["completed"][number]) : null;
                    return (
                      <div
                        key={b.id}
                        className="flex items-start gap-3 rounded-lg border border-zinc-100 bg-zinc-50 p-3 opacity-70"
                      >
                        <span className="mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-zinc-400 text-xs text-white">✓</span>
                        <div className="min-w-0 space-y-0.5">
                          <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                            <span className="font-semibold text-zinc-900 text-sm">
                              {adminB ? adminB.vessel.boatName : custB?.vessel.boatName}
                            </span>
                            {b.vessel?.yardNumber ? (
                              <span className="text-xs font-medium text-zinc-500">Yard #{b.vessel.yardNumber}</span>
                            ) : null}
                            {b.vessel?.owner?.username ? (
                              <span className="rounded-full bg-zinc-100 px-2 py-0.5 text-xs font-bold text-zinc-600">@{b.vessel.owner.username}</span>
                            ) : null}
                          </div>
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-zinc-500">
                            {adminB ? (
                              <>
                                {adminB.vessel.boatNumber ? <span>#{adminB.vessel.boatNumber}</span> : null}
                                <span>{adminB.vessel.owner.name}</span>
                                {adminB.vessel.owner.phone ? (
                                  <a href={`tel:${adminB.vessel.owner.phone}`} className="text-sky-600 hover:underline">{adminB.vessel.owner.phone}</a>
                                ) : null}
                              </>
                            ) : (
                              <span>{custB?.vessel.owner.name}</span>
                            )}
                          </div>
                          <div className="flex flex-wrap items-center gap-2 mt-1">
                            {b.stayingOnMooring ? (
                              <span className="inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-700">
                                Staying on mooring
                              </span>
                            ) : null}
                            <span className="text-xs text-zinc-400">
                              Completed {b.completedAt ? new Date(b.completedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}
                            </span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8">
      {/* Page header */}
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight">Live Queues</h1>
          <p className="mt-1 text-sm text-zinc-600">Both queues · auto-refreshes every 3 minutes.</p>
        </div>
        <Button variant="secondary" onClick={load} disabled={loading}>
          Refresh
        </Button>
      </div>

      {/* Launch Queue Section */}
      {renderQueueSection("LAUNCH", launchData)}

      {/* Retrieval Queue Section */}
      {renderQueueSection("RETRIEVAL", retrievalData)}
    </div>
  );
}

