"use client";

import * as React from "react";
import Link from "next/link";
import { getSocket } from "@/lib/socketClient";
import { playLaunchAlert, playRetrievalAlert } from "@/lib/queueSounds";
import { triggerBoatAnimation } from "@/components/boat-animation";
import type { QueueResponseAdminDTO } from "@/lib/apiTypes";

type QueueType = "LAUNCH" | "RETRIEVAL";

const THEME = {
  LAUNCH: {
    bg: "bg-emerald-950",
    header: "from-emerald-900 to-teal-800",
    accent: "bg-emerald-500",
    accentHover: "hover:bg-emerald-400",
    accentText: "text-emerald-300",
    accentMuted: "text-emerald-400/60",
    ring: "ring-emerald-500/40",
    badge: "bg-emerald-400 text-emerald-950",
    badgeMuted: "bg-white/10 text-emerald-300",
    completedBtn: "bg-emerald-600 hover:bg-emerald-500 text-white",
    label: "Launch",
    subtitle: "Setting Sail",
    actionLabel: "Mark Launched",
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="h-8 w-8 text-emerald-300">
        <path d="M12 19V5M5 12l7-7 7 7" strokeLinecap="round" strokeLinejoin="round" />
        <path d="M3 19h18" strokeLinecap="round" />
      </svg>
    ),
    wave: "M0 40 Q300 0 600 40 Q900 80 1200 40 L1200 80 L0 80Z",
    waveColor: "text-emerald-800/30",
    otherHref: "/office/retrieval",
    otherLabel: "Go to Retrieval →",
  },
  RETRIEVAL: {
    bg: "bg-orange-950",
    header: "from-orange-900 to-amber-800",
    accent: "bg-amber-500",
    accentHover: "hover:bg-amber-400",
    accentText: "text-amber-300",
    accentMuted: "text-amber-400/60",
    ring: "ring-amber-500/40",
    badge: "bg-amber-400 text-amber-950",
    badgeMuted: "bg-white/10 text-amber-300",
    completedBtn: "bg-amber-600 hover:bg-amber-500 text-white",
    label: "Retrieval",
    subtitle: "Return to Dock",
    actionLabel: "Mark Retrieved",
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="h-8 w-8 text-amber-300">
        <path d="M12 5v14M5 12l7 7 7-7" strokeLinecap="round" strokeLinejoin="round" />
        <path d="M3 5h18" strokeLinecap="round" />
      </svg>
    ),
    wave: "M0 50 Q200 20 400 50 Q600 80 800 50 Q1000 20 1200 50 L1200 80 L0 80Z",
    waveColor: "text-orange-900/40",
    otherHref: "/office/launch",
    otherLabel: "← Go to Launch",
  },
} as const;

export function AdminOfficeClient({ type }: { type: QueueType }) {
  const t = THEME[type];
  const [data, setData] = React.useState<QueueResponseAdminDTO | null>(null);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string | null>(null);
  const [actionId, setActionId] = React.useState<string | null>(null);
  const [actionError, setActionError] = React.useState<string | null>(null);
  const [lastRefresh, setLastRefresh] = React.useState<Date | null>(null);

  async function load(silent = false) {
    if (!silent) setLoading(true);
    setError(null);
    const res = await fetch(`/api/queues/${type}`, { cache: "no-store" });
    if (!res.ok) { setError("Failed to load queue"); setLoading(false); return; }
    setData(await res.json());
    setLastRefresh(new Date());
    setLoading(false);
  }

  async function markCompleted(id: string) {
    setActionId(id);
    setActionError(null);
    const res = await fetch(`/api/admin/bookings/${id}`, {
      method: "PATCH",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ action: "MARK_COMPLETED" }),
    });
    if (!res.ok) {
      const j = await res.json().catch(() => null) as { error?: string } | null;
      setActionError(j?.error ?? "Action failed");
    } else {
      triggerBoatAnimation(type === "LAUNCH" ? "launch" : "retrieval");
      await load(true);
    }
    setActionId(null);
  }

  async function cancelBooking(id: string) {
    if (!window.confirm("Remove this vessel from the queue?")) return;
    setActionId(id);
    setActionError(null);
    const res = await fetch(`/api/admin/bookings/${id}`, {
      method: "PATCH",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ action: "CANCEL" }),
    });
    if (!res.ok) {
      const j = await res.json().catch(() => null) as { error?: string } | null;
      setActionError(j?.error ?? "Cancel failed");
    } else {
      await load(true);
    }
    setActionId(null);
  }

  async function toggleMooring(id: string, val: boolean) {
    setActionId(id);
    await fetch(`/api/admin/bookings/${id}`, {
      method: "PATCH",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ action: "SET_MOORING", stayingOnMooring: val }),
    });
    await load(true);
    setActionId(null);
  }

  React.useEffect(() => {
    load();
    let active = true;
    const interval = setInterval(() => { if (active) load(true); }, 60 * 1000); // refresh every 1 min in office
    (async () => {
      const socket = await getSocket();
      if (!active) return;
      socket.emit("queues:subscribe", {});
      socket.on("queues:updated", () => { load(true); type === "LAUNCH" ? playLaunchAlert() : playRetrievalAlert(); });
    })();
    return () => { active = false; clearInterval(interval); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [type]);

  const pending = data?.pending ?? [];
  const completed = data?.completed ?? [];

  return (
    <div className={`min-h-screen ${t.bg} flex flex-col`}>
      {/* Header */}
      <div className={`relative overflow-hidden bg-gradient-to-r ${t.header} px-6 py-6 shadow-lg`}>
        <svg aria-hidden="true" className={`absolute bottom-0 left-0 w-full ${t.waveColor}`} viewBox="0 0 1200 80" preserveAspectRatio="none">
          <path d={t.wave} fill="currentColor" />
        </svg>
        <div className="relative flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-center gap-4">
