            {data?.dailyMessage?.message ? (
              <div className="max-w-xs rounded-xl bg-white/10 px-4 py-2 backdrop-blur-sm ring-1 ring-white/15">
                <p className={`text-xs font-semibold ${t.accentText}`}>Today</p>
                <p className="text-xs text-white/80">{data.dailyMessage.message}</p>
              </div>
            ) : null}
            <Link href={t.otherHref}
              className="rounded-xl bg-white/10 px-4 py-2 text-xs font-semibold text-white ring-1 ring-white/20 transition hover:bg-white/20">
              {t.otherLabel}
            </Link>
            <Link href="/admin"
              className="rounded-xl bg-white/10 px-4 py-2 text-xs font-semibold text-white ring-1 ring-white/20 transition hover:bg-white/20">
              ← Admin
            </Link>
            <button onClick={() => load()} disabled={loading}
              className="flex items-center gap-1.5 rounded-xl bg-white/15 px-4 py-2 text-xs font-semibold text-white ring-1 ring-white/20 transition hover:bg-white/25 disabled:opacity-50">
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" className="h-3.5 w-3.5">
                <path d="M2 8a6 6 0 1 0 1-3.3M2 2v4h4" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
              Refresh
            </button>
          </div>
        </div>
      </div>

      {/* Action error bar */}
      {actionError ? (
        <div className="flex items-center justify-between bg-red-900/60 px-6 py-2 text-sm text-red-300 ring-1 ring-red-500/30">
          <span>{actionError}</span>
          <button onClick={() => setActionError(null)} className="text-red-400 hover:text-white">✕</button>
        </div>
      ) : null}

      {/* Body */}
      <div className="flex flex-1 flex-col gap-0 overflow-hidden lg:flex-row">
        {/* ── Pending column ── */}
        <div className="flex flex-1 flex-col overflow-hidden border-r border-white/5">
          <div className="flex items-center justify-between border-b border-white/10 px-6 py-3">
            <h2 className={`text-xs font-bold uppercase tracking-widest ${t.accentText}`}>
              Pending ({pending.length})
            </h2>
          </div>

          {error ? (
            <div className="m-4 rounded-xl bg-red-900/40 p-4 text-sm text-red-300">{error}</div>
          ) : loading && pending.length === 0 ? (
            <div className="space-y-3 p-6">
              {[...Array(4)].map((_, i) => <div key={i} className="h-24 animate-pulse rounded-2xl bg-white/5" />)}
            </div>
          ) : pending.length === 0 ? (
            <div className="flex flex-1 flex-col items-center justify-center py-20 text-center">
              <div className={`mb-3 flex h-14 w-14 items-center justify-center rounded-full bg-white/5 ${t.accentText}`}>
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="h-7 w-7">
                  <path d="M5 13l4 4L19 7" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              </div>
              <p className="font-semibold text-white">Queue is clear</p>
              <p className={`mt-1 text-sm ${t.accentMuted}`}>No {t.label.toLowerCase()} requests pending.</p>
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto p-4 space-y-3">
              {pending.map((b, i) => {
                const isFirst = i === 0;
                return (
                  <div key={b.id} className={`relative overflow-hidden rounded-2xl ring-1 ${isFirst ? `ring-1 ${t.ring} bg-white/10 shadow-lg` : "bg-white/5 ring-white/8 hover:bg-white/8"} transition-all`}>
                    {isFirst && <div className={`absolute inset-y-0 left-0 w-1.5 rounded-l-2xl ${t.accent}`} />}
                    <div className="flex items-start gap-4 px-5 py-4 pl-6">
                      {/* Position */}
                      <div className={`mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-xl text-base font-black ${isFirst ? t.badge : t.badgeMuted}`}>
                        {i + 1}
                      </div>
                      {/* Info */}
                      <div className="min-w-0 flex-1">
                        <div className="flex flex-wrap items-center gap-2">
                          <span className="text-base font-bold text-white">{b.vessel.boatName}</span>
                          {b.vessel.yardNumber ? (
                            <span className={`rounded-full bg-white/10 px-2 py-0.5 text-xs font-semibold ${t.accentText}`}>
                              Yard #{b.vessel.yardNumber}
                            </span>
                          ) : null}
                          {b.stayingOnMooring ? (
                            <span className="rounded-full bg-sky-500/20 px-2 py-0.5 text-xs font-semibold text-sky-300 ring-1 ring-sky-400/30">
                              Mooring
                            </span>
                          ) : null}
                        </div>
                        <div className="mt-1.5 flex flex-wrap items-center gap-x-3 gap-y-0.5 text-sm">
                          {b.vessel.owner.username ? (
