   195→        <div className="relative">
   196→          <p className="text-xs font-semibold uppercase tracking-widest text-sky-300">Boat launch &amp; retrieval</p>
   197→          <h1 className="mt-1 text-2xl font-bold tracking-tight">Good day, {userName}</h1>
   198→          {userHandle ? (
   199→            <p className="mt-0.5 text-sm font-medium text-sky-300">@{userHandle}</p>
   200→          ) : null}
   201→          <p className="mt-2 max-w-md text-sm text-sky-100">
   202→            Book a same-day launch or retrieval below. Your position in the live queue updates in real time.
   203→          </p>
   204→          <div className="mt-5 flex flex-wrap gap-3">
   205→            <div className="rounded-xl bg-white/10 px-4 py-3 backdrop-blur-sm">
   206→              <div className="text-2xl font-bold">{vessels.length}</div>
   207→              <div className="text-xs text-sky-200">Vessel{vessels.length !== 1 ? "s" : ""}</div>
   208→            </div>
   209→            <div className="rounded-xl bg-white/10 px-4 py-3 backdrop-blur-sm">
   210→              <div className="text-2xl font-bold">{activeBookings}</div>
   211→              <div className="text-xs text-sky-200">Active booking{activeBookings !== 1 ? "s" : ""} today</div>
   212→            </div>
   213→            <Link href="/queue/LAUNCH" className="rounded-xl bg-white/10 px-4 py-3 backdrop-blur-sm transition-colors hover:bg-white/20">
   214→              <div className="text-xs text-sky-200">Launch queue</div>
   215→              <div className="mt-0.5 flex items-center gap-1 text-sm font-semibold">
   216→                {queueCounts !== null ? (
   217→                  <span className="rounded-full bg-emerald-400/30 px-2 py-0.5 text-xs font-bold text-emerald-200">{queueCounts.launch} waiting</span>
   218→                ) : null}
   219→                <BoatIcon />
   220→              </div>
   221→            </Link>
   222→            <Link href="/queue/RETRIEVAL" className="rounded-xl bg-white/10 px-4 py-3 backdrop-blur-sm transition-colors hover:bg-white/20">
   223→              <div className="text-xs text-sky-200">Retrieval queue</div>
   224→              <div className="mt-0.5 flex items-center gap-1 text-sm font-semibold">
   225→                {queueCounts !== null ? (
   226→                  <span className="rounded-full bg-orange-400/30 px-2 py-0.5 text-xs font-bold text-orange-200">{queueCounts.retrieval} waiting</span>
   227→                ) : null}
   228→                <BoatIconDown />
   229→              </div>
   230→            </Link>
   231→          </div>
   232→        </div>
   233→      </div>
   234→
   235→      {/* Error */}
   236→      {error ? (
   237→        <div className="flex items-start gap-3 rounded-xl border border-red-200 bg-red-50 p-4">
   238→          <svg className="mt-0.5 h-4 w-4 shrink-0 text-red-500" viewBox="0 0 24 24" fill="currentColor">
   239→            <path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm0 11a1 1 0 01-1-1V8a1 1 0 112 0v4a1 1 0 01-1 1zm0 4a1 1 0 110-2 1 1 0 010 2z" />
   240→          </svg>
   241→          <p className="text-sm text-red-700">{error}</p>
   242→        </div>
   243→      ) : null}
   244→
   245→      {/* Booking confirmation */}
   246→      {bookingResult ? (
   247→        <div className="overflow-hidden rounded-2xl border border-emerald-200 bg-white shadow-sm">
   248→          <div className="bg-gradient-to-r from-emerald-500 to-teal-500 px-5 py-3">
   249→            <div className="flex items-center justify-between">
   250→              <span className="text-sm font-semibold text-white">Booking confirmed</span>
   251→              <span className="rounded-full bg-white/25 px-3 py-0.5 text-sm font-bold text-white">
   252→                Position #{bookingResult.position}
   253→              </span>
   254→            </div>
   255→          </div>
   256→          <div className="p-5">
   257→            <p className="text-sm text-zinc-700">
   258→              <span className="font-semibold text-zinc-900">{bookingResult.vesselName}</span> has been added to the{" "}
   259→              <span className="font-medium">{bookingResult.type === "LAUNCH" ? "launch" : "retrieval"}</span> queue.
   260→            </p>
   261→            {bookingResult.queue.length > 0 ? (
   262→              <div className="mt-4">
   263→                <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-zinc-400">
   264→                  Queue snapshot — {bookingResult.queue.length} vessels
   265→                </p>
   266→                <div className="flex flex-wrap gap-1.5">
   267→                  {bookingResult.queue.slice(0, 15).map((yardNum, i) => (
   268→                    <span
   269→                      key={i}
   270→                      className={[
   271→                        "inline-flex items-center gap-1 rounded-lg px-2.5 py-1 text-xs font-medium",
   272→                        i + 1 === bookingResult.position
   273→                          ? "bg-emerald-500 text-white ring-2 ring-emerald-300"
   274→                          : "bg-zinc-100 text-zinc-600",
   275→                      ].join(" ")}
   276→                    >
   277→                      <span className="opacity-60">{i + 1}.</span> {yardNum}
   278→                    </span>
   279→                  ))}
   280→                  {bookingResult.queue.length > 15 ? (
   281→                    <span className="rounded-lg bg-zinc-100 px-2.5 py-1 text-xs text-zinc-400">
   282→                      +{bookingResult.queue.length - 15} more
   283→                    </span>
   284→                  ) : null}
   285→                </div>
   286→              </div>
   287→            ) : null}
   288→            <div className="mt-4 flex flex-wrap gap-2">
   289→              <Link href="/queue">
   290→                <Button size="sm">Open live queue</Button>
   291→              </Link>
   292→              <Button size="sm" variant="ghost" onClick={() => setBookingResult(null)}>Dismiss</Button>
   293→            </div>
   294→          </div>
   295→        </div>
   296→      ) : null}
   297→
   298→      {/* Vessels */}
   299→      <div>
   300→        <div className="mb-3 flex items-center justify-between">
   301→          <h2 className="text-base font-semibold text-zinc-900">My vessels</h2>
   302→          <button
   303→            onClick={() => setShowAddVessel((v) => !v)}
   304→            className="rounded-lg bg-zinc-100 px-3 py-1.5 text-xs font-semibold text-zinc-600 transition hover:bg-sky-100 hover:text-sky-700"
   305→          >
   306→            {showAddVessel ? "Cancel" : "+ Add vessel"}
   307→          </button>
   308→        </div>
   309→
   310→        {showAddVessel ? (
   311→          <form onSubmit={addVessel} className="mb-4 overflow-hidden rounded-2xl border border-sky-200 bg-sky-50 p-5 space-y-3">
   312→            <p className="text-xs font-semibold uppercase tracking-wide text-sky-700">New vessel</p>
   313→            <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
   314→              <div className="space-y-1">
   315→                <label className="text-xs font-semibold text-zinc-500">Boat name *</label>
   316→                <Input required value={addVesselForm.boatName} onChange={(e) => setAddVesselForm((f) => ({ ...f, boatName: e.target.value }))} placeholder="Sea Breeze" />
   317→              </div>
   318→              <div className="space-y-1">
   319→                <label className="text-xs font-semibold text-zinc-500">Registration # *</label>
   320→                <Input required value={addVesselForm.boatNumber} onChange={(e) => setAddVesselForm((f) => ({ ...f, boatNumber: e.target.value }))} placeholder="BC1234" />
   321→              </div>
   322→              <div className="space-y-1">
   323→                <label className="text-xs font-semibold text-zinc-500">Boat type</label>
   324→                <Input value={addVesselForm.boatType} onChange={(e) => setAddVesselForm((f) => ({ ...f, boatType: e.target.value }))} placeholder="Sailboat, Powerboat…" />
   325→              </div>
   326→              <div className="space-y-1">
   327→                <label className="text-xs font-semibold text-zinc-500">Yard #</label>
   328→                <Input value={addVesselForm.yardNumber} onChange={(e) => setAddVesselForm((f) => ({ ...f, yardNumber: e.target.value }))} placeholder="YD102" />
   329→              </div>
   330→            </div>
   331→            <div className="flex gap-2 pt-1">
   332→              <Button type="submit" size="sm" disabled={addVesselPending}>
   333→                {addVesselPending ? "Adding…" : "Add vessel"}
   334→              </Button>
   335→              <Button type="button" size="sm" variant="ghost" onClick={() => setShowAddVessel(false)}>Cancel</Button>
   336→            </div>
   337→          </form>
   338→        ) : null}
   339→        {vessels.length === 0 ? (
   340→          <div className="rounded-2xl border border-dashed border-zinc-300 bg-white p-10 text-center">
   341→            <div className="mx-auto mb-3 flex h-12 w-12 items-center justify-center rounded-full bg-zinc-100 text-zinc-400">
   342→              <AnchorIcon />
   343→            </div>
   344→            <p className="text-sm font-medium text-zinc-600">No vessels registered yet.</p>
   345→            <p className="mt-1 text-xs text-zinc-400">Register a vessel from your account to get started.</p>
   346→          </div>
   347→        ) : (
   348→          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
   349→            {vessels.map((v) => {
   350→              const bookedFromServer = new Set(v.bookings.map((b) => b.type));
   351→              const bookedLocally = localBooked[v.id] ?? new Set<BookingType>();
   352→              const hasLaunch = bookedFromServer.has("LAUNCH") || bookedLocally.has("LAUNCH");
   353→              const hasRetrieval = bookedFromServer.has("RETRIEVAL") || bookedLocally.has("RETRIEVAL");
   354→              const isStayingOut = v.stayingOnMooring || !!localStayingOut[v.id];
   355→              const isActive = hasLaunch || hasRetrieval || isStayingOut;
   356→
   357→              return (
   358→                <div
   359→                  key={v.id}
   360→                  className={[
   361→                    "group relative overflow-hidden rounded-2xl border bg-white shadow-sm transition-shadow hover:shadow-md",
   362→                    isActive ? "border-sky-200" : "border-zinc-200",
   363→                  ].join(" ")}
   364→                >
   365→                  <div
   366→                    className={[
   367→                      "absolute left-0 top-0 h-full w-1",
   368→                      isActive ? "bg-gradient-to-b from-sky-400 to-cyan-500" : "bg-zinc-100",
   369→                    ].join(" ")}
   370→                  />
   371→                  <div className="p-5 pl-6">
   372→                    <div className="flex items-start justify-between gap-3">
   373→                      <div className="flex items-center gap-3">
   374→                        <div className={[
   375→                          "flex h-10 w-10 items-center justify-center rounded-xl",
   376→                          isActive ? "bg-sky-50 text-sky-600" : "bg-zinc-50 text-zinc-400",
   377→                        ].join(" ")}>
   378→                          <AnchorIcon />
   379→                        </div>
   380→                        <div>
   381→                          <div className="font-semibold leading-tight text-zinc-900">{v.boatName}</div>
   382→                          <div className="mt-0.5 text-xs text-zinc-400">
   383→                            {[v.boatType, v.yardNumber ? "Yard " + v.yardNumber : null, "#" + v.boatNumber]
   384→                              .filter(Boolean)
   385→                              .join(" · ")}
   386→                          </div>
   387→                        </div>
   388→                      </div>
   389→                      <div className="flex items-center gap-2">
   390→                        <div
   391→                          className={["h-2 w-2 rounded-full", isActive ? "bg-emerald-400" : "bg-zinc-200"].join(" ")}
   392→                          title={isActive ? "Active booking" : "No bookings"}
   393→                        />
   394→                        <button
   395→                          onClick={() => removeVessel(v.id)}
   396→                          className="rounded-lg px-2 py-0.5 text-xs font-medium text-zinc-400 transition hover:bg-red-50 hover:text-red-500"
   397→                          title="Remove vessel"
   398→                        >
   399→                          Remove
   400→                        </button>
   401→                      </div>
   402→                    </div>
   403→
   404→                    {isActive ? (
   405→                      <div className="mt-3 flex flex-wrap gap-1.5">
   406→                        {hasLaunch ? (
   407→                          <span className="inline-flex items-center gap-1 rounded-full bg-sky-50 px-2.5 py-0.5 text-xs font-medium text-sky-700 ring-1 ring-sky-200">
   408→                            <span className="h-1.5 w-1.5 rounded-full bg-sky-400" />
   409→                            Launch queued
   410→                          </span>
   411→                        ) : null}
   412→                        {hasRetrieval ? (
   413→                          <span className="inline-flex items-center gap-1 rounded-full bg-violet-50 px-2.5 py-0.5 text-xs font-medium text-violet-700 ring-1 ring-violet-200">
   414→                            <span className="h-1.5 w-1.5 rounded-full bg-violet-400" />
   415→                            Retrieval queued
   416→                          </span>
   417→                        ) : null}
   418→                        {isStayingOut ? (
   419→                          <span className="inline-flex items-center gap-1 rounded-full bg-amber-50 px-2.5 py-0.5 text-xs font-medium text-amber-700 ring-1 ring-amber-200">
   420→                            <span className="h-1.5 w-1.5 rounded-full bg-amber-400" />
   421→                            Staying out
   422→                          </span>
   423→                        ) : null}
   424→                      </div>
   425→                    ) : (
   426→                      <p className="mt-3 text-xs text-zinc-400">No bookings today</p>
   427→                    )}
   428→
   429→                    <div className="my-4 border-t border-zinc-100" />
   430→
   431→                    <div className={`grid gap-2 ${isStayingOut || v.canRetrieve ? "grid-cols-2" : "grid-cols-2"}`}>
   432→                      {hasLaunch ? (
   433→                        <Link href="/queue" className="contents">
   434→                          <button className="flex items-center justify-center gap-1.5 rounded-xl bg-sky-600 px-3 py-2.5 text-xs font-semibold text-white transition-colors hover:bg-sky-500">
   435→                            Launch queue <BoatIcon />
   436→                          </button>
   437→                        </Link>
   438→                      ) : (
   439→                        <button
   440→                          className="flex items-center justify-center gap-1.5 rounded-xl border border-zinc-200 bg-zinc-50 px-3 py-2.5 text-xs font-semibold text-zinc-700 transition-colors hover:bg-zinc-100 disabled:opacity-50"
   441→                          disabled={pending && pendingAction === v.id + "-LAUNCH"}
   442→                          onClick={() => book(v, "LAUNCH")}
   443→                        >
   444→                          {pending && pendingAction === v.id + "-LAUNCH" ? <span className="animate-pulse">Booking\u2026</span> : "Book launch"}
   445→                        </button>
   446→                      )}
   447→
   448→                      {hasRetrieval ? (
   449→                        <Link href="/queue" className="contents">
   450→                          <button className="flex items-center justify-center gap-1.5 rounded-xl bg-violet-600 px-3 py-2.5 text-xs font-semibold text-white transition-colors hover:bg-violet-500">
