   365→}) {
   366→  const borderColor = accent === "sky" ? "border-sky-200/60" : "border-teal-200/60";
   367→  const headerBorder = accent === "sky" ? "border-sky-100/60" : "border-teal-100/60";
   368→  const iconColor = accent === "sky" ? "text-sky-600" : "text-teal-600";
   369→  const labelColor = accent === "sky" ? "text-sky-700" : "text-teal-700";
   370→
   371→  return (
   372→    <div className={`overflow-hidden rounded-2xl border ${borderColor} bg-white/70 shadow-sm backdrop-blur-sm`}>
