                                  {custB?.vessel.boatType ? <span>{custB.vessel.boatType}</span> : null}
                                  <span className="font-medium text-zinc-700">{custB?.vessel.owner.name}</span>
                                </>
                              )}
                            </div>
                            <div className="flex flex-wrap items-center gap-2 mt-1">
                              {b.stayingOnMooring ? (
                                <span className="inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-700">
                                  Staying on mooring
                                </span>
                              ) : null}
                              <span className="text-xs text-zinc-400">
                                {b.requestedAt ? new Date(b.requestedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}
                              </span>
                            </div>
                          </div>
                        </div>
                        {isAdmin ? (
                          <Button
                            size="sm"
                            variant="secondary"
                            className="shrink-0 text-xs"
                            disabled={actionPendingId === b.id}
                            onClick={() => markCompleted(b.id, type)}
                          >
                            {actionPendingId === b.id ? "…" : buttonLabel}
                          </Button>
                        ) : null}
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Completed */}
          <Card>
            <CardHeader>
              <CardTitle>Completed ({completed.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {loading ? (
                <div className="text-sm text-zinc-600">Loading…</div>
              ) : completed.length === 0 ? (
                <div className="text-sm text-zinc-600">None completed yet.</div>
              ) : (
                <div className="space-y-2">
                  {completed.map((b) => {
                    const adminB = isAdmin ? (b as QueueResponseAdminDTO["completed"][number]) : null;
                    const custB = !isAdmin ? (b as QueueResponseCustomerDTO["completed"][number]) : null;
                    return (
                      <div
                        key={b.id}
                        className="flex items-start gap-3 rounded-lg border border-zinc-100 bg-zinc-50 p-3 opacity-70"
                      >
                        <span className="mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-zinc-400 text-xs text-white">✓</span>
                        <div className="min-w-0 space-y-0.5">
                          <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                            <span className="font-semibold text-zinc-900 text-sm">
                              {adminB ? adminB.vessel.boatName : custB?.vessel.boatName}
                            </span>
                            {b.vessel?.yardNumber ? (
                              <span className="text-xs font-medium text-zinc-500">Yard #{b.vessel.yardNumber}</span>
                            ) : null}
                            {b.vessel?.owner?.username ? (
                              <span className="rounded-full bg-zinc-100 px-2 py-0.5 text-xs font-bold text-zinc-600">@{b.vessel.owner.username}</span>
                            ) : null}
                          </div>
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-zinc-500">
                            {adminB ? (
                              <>
                                {adminB.vessel.boatNumber ? <span>#{adminB.vessel.boatNumber}</span> : null}
                                <span>{adminB.vessel.owner.name}</span>
                                {adminB.vessel.owner.phone ? (
                                  <a href={`tel:${adminB.vessel.owner.phone}`} className="text-sky-600 hover:underline">{adminB.vessel.owner.phone}</a>
                                ) : null}
                              </>
                            ) : (
                              <span>{custB?.vessel.owner.name}</span>
                            )}
                          </div>
                          <div className="flex flex-wrap items-center gap-2 mt-1">
                            {b.stayingOnMooring ? (
                              <span className="inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-700">
                                Staying on mooring
                              </span>
                            ) : null}
                            <span className="text-xs text-zinc-400">
                              Completed {b.completedAt ? new Date(b.completedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}
                            </span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8">
      {/* Page header */}
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight">Live Queues</h1>
          <p className="mt-1 text-sm text-zinc-600">Both queues · auto-refreshes every 3 minutes.</p>
        </div>
        <Button variant="secondary" onClick={load} disabled={loading}>
          Refresh
        </Button>
      </div>

      {/* Launch Queue Section */}
      {renderQueueSection("LAUNCH", launchData)}

      {/* Retrieval Queue Section */}
      {renderQueueSection("RETRIEVAL", retrievalData)}
    </div>
  );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { getSocket } from "@/lib/socketClient";
import { playLaunchAlert, playRetrievalAlert } from "@/lib/queueSounds";
import { triggerBoatAnimation } from "@/components/boat-animation";
import type { QueueResponseAdminDTO } from "@/lib/apiTypes";

type QueueType = "LAUNCH" | "RETRIEVAL";

const THEME = {
  LAUNCH: {
    bg: "bg-emerald-950",
    header: "from-emerald-900 to-teal-800",
    accent: "bg-emerald-500",
    accentHover: "hover:bg-emerald-400",
    accentText: "text-emerald-300",
    accentMuted: "text-emerald-400/60",
    ring: "ring-emerald-500/40",
    badge: "bg-emerald-400 text-emerald-950",
    badgeMuted: "bg-white/10 text-emerald-300",
    completedBtn: "bg-emerald-600 hover:bg-emerald-500 text-white",
    label: "Launch",
    subtitle: "Setting Sail",
    actionLabel: "Mark Launched",
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="h-8 w-8 text-emerald-300">
        <path d="M12 19V5M5 12l7-7 7 7" strokeLinecap="round" strokeLinejoin="round" />
        <path d="M3 19h18" strokeLinecap="round" />
      </svg>
    ),
    wave: "M0 40 Q300 0 600 40 Q900 80 1200 40 L1200 80 L0 80Z",
    waveColor: "text-emerald-800/30",
    otherHref: "/office/retrieval",
    otherLabel: "Go to Retrieval →",
  },
  RETRIEVAL: {
    bg: "bg-orange-950",
    header: "from-orange-900 to-amber-800",
    accent: "bg-amber-500",
    accentHover: "hover:bg-amber-400",
    accentText: "text-amber-300",
    accentMuted: "text-amber-400/60",
    ring: "ring-amber-500/40",
    badge: "bg-amber-400 text-amber-950",
    badgeMuted: "bg-white/10 text-amber-300",
    completedBtn: "bg-amber-600 hover:bg-amber-500 text-white",
    label: "Retrieval",
    subtitle: "Return to Dock",
    actionLabel: "Mark Retrieved",
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="h-8 w-8 text-amber-300">
        <path d="M12 5v14M5 12l7 7 7-7" strokeLinecap="round" strokeLinejoin="round" />
        <path d="M3 5h18" strokeLinecap="round" />
      </svg>
    ),
    wave: "M0 50 Q200 20 400 50 Q600 80 800 50 Q1000 20 1200 50 L1200 80 L0 80Z",
    waveColor: "text-orange-900/40",
    otherHref: "/office/launch",
    otherLabel: "← Go to Launch",
  },
} as const;

export function AdminOfficeClient({ type }: { type: QueueType }) {
  const t = THEME[type];
  const [data, setData] = React.useState<QueueResponseAdminDTO | null>(null);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string | null>(null);
  const [actionId, setActionId] = React.useState<string | null>(null);
  const [actionError, setActionError] = React.useState<string | null>(null);
  const [lastRefresh, setLastRefresh] = React.useState<Date | null>(null);

  async function load(silent = false) {
    if (!silent) setLoading(true);
    setError(null);
    const res = await fetch(`/api/queues/${type}`, { cache: "no-store" });
    if (!res.ok) { setError("Failed to load queue"); setLoading(false); return; }
    setData(await res.json());
    setLastRefresh(new Date());
    setLoading(false);
  }

  async function markCompleted(id: string) {
    setActionId(id);
    setActionError(null);
    const res = await fetch(`/api/admin/bookings/${id}`, {
      method: "PATCH",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ action: "MARK_COMPLETED" }),
    });
    if (!res.ok) {
      const j = await res.json().catch(() => null) as { error?: string } | null;
      setActionError(j?.error ?? "Action failed");
    } else {
      triggerBoatAnimation(type === "LAUNCH" ? "launch" : "retrieval");
      await load(true);
    }
    setActionId(null);
  }

  async function cancelBooking(id: string) {
    if (!window.confirm("Remove this vessel from the queue?")) return;
    setActionId(id);
    setActionError(null);
    const res = await fetch(`/api/admin/bookings/${id}`, {
      method: "PATCH",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ action: "CANCEL" }),
    });
    if (!res.ok) {
      const j = await res.json().catch(() => null) as { error?: string } | null;
      setActionError(j?.error ?? "Cancel failed");
    } else {
      await load(true);
    }
    setActionId(null);
  }

  async function toggleMooring(id: string, val: boolean) {
    setActionId(id);
    await fetch(`/api/admin/bookings/${id}`, {
      method: "PATCH",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ action: "SET_MOORING", stayingOnMooring: val }),
    });
    await load(true);
    setActionId(null);
  }

  React.useEffect(() => {
    load();
    let active = true;
    const interval = setInterval(() => { if (active) load(true); }, 60 * 1000); // refresh every 1 min in office
    (async () => {
      const socket = await getSocket();
      if (!active) return;
      socket.emit("queues:subscribe", {});
      socket.on("queues:updated", () => { load(true); type === "LAUNCH" ? playLaunchAlert() : playRetrievalAlert(); });
    })();
    return () => { active = false; clearInterval(interval); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [type]);

  const pending = data?.pending ?? [];
  const completed = data?.completed ?? [];

  return (
    <div className={`min-h-screen ${t.bg} flex flex-col`}>
      {/* Header */}
      <div className={`relative overflow-hidden bg-gradient-to-r ${t.header} px-6 py-6 shadow-lg`}>
        <svg aria-hidden="true" className={`absolute bottom-0 left-0 w-full ${t.waveColor}`} viewBox="0 0 1200 80" preserveAspectRatio="none">
          <path d={t.wave} fill="currentColor" />
        </svg>
        <div className="relative flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="flex h-16 w-16 items-center justify-center rounded-2xl bg-white/10 ring-1 ring-white/20 backdrop-blur-sm">
              {t.icon}
            </div>
            <div>
              <p className={`text-xs font-bold uppercase tracking-widest ${t.accentText}`}>{t.subtitle}</p>
              <h1 className="text-3xl font-black tracking-tight text-white">{t.label} Queue</h1>
              <p className="mt-0.5 text-sm text-white/50">
                Admin office view · {pending.length} pending · {completed.length} done
                {lastRefresh ? <span> · refreshed {lastRefresh.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" })}</span> : null}
              </p>
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-3">
            {/* Daily message chip */}
            {data?.dailyMessage?.message ? (
              <div className="max-w-xs rounded-xl bg-white/10 px-4 py-2 backdrop-blur-sm ring-1 ring-white/15">
                <p className={`text-xs font-semibold ${t.accentText}`}>Today</p>
                <p className="text-xs text-white/80">{data.dailyMessage.message}</p>
              </div>
            ) : null}
            <Link href={t.otherHref}
              className="rounded-xl bg-white/10 px-4 py-2 text-xs font-semibold text-white ring-1 ring-white/20 transition hover:bg-white/20">
              {t.otherLabel}
            </Link>
            <Link href="/admin"
              className="rounded-xl bg-white/10 px-4 py-2 text-xs font-semibold text-white ring-1 ring-white/20 transition hover:bg-white/20">
              ← Admin
            </Link>
            <button onClick={() => load()} disabled={loading}
              className="flex items-center gap-1.5 rounded-xl bg-white/15 px-4 py-2 text-xs font-semibold text-white ring-1 ring-white/20 transition hover:bg-white/25 disabled:opacity-50">
              <svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" className="h-3.5 w-3.5">
                <path d="M2 8a6 6 0 1 0 1-3.3M2 2v4h4" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
              Refresh
            </button>
          </div>
        </div>
      </div>

      {/* Action error bar */}
      {actionError ? (
        <div className="flex items-center justify-between bg-red-900/60 px-6 py-2 text-sm text-red-300 ring-1 ring-red-500/30">
          <span>{actionError}</span>
          <button onClick={() => setActionError(null)} className="text-red-400 hover:text-white">✕</button>
        </div>
      ) : null}

      {/* Body */}
      <div className="flex flex-1 flex-col gap-0 overflow-hidden lg:flex-row">
        {/* ── Pending column ── */}
        <div className="flex flex-1 flex-col overflow-hidden border-r border-white/5">
          <div className="flex items-center justify-between border-b border-white/10 px-6 py-3">
            <h2 className={`text-xs font-bold uppercase tracking-widest ${t.accentText}`}>
              Pending ({pending.length})
            </h2>
          </div>

          {error ? (
            <div className="m-4 rounded-xl bg-red-900/40 p-4 text-sm text-red-300">{error}</div>
          ) : loading && pending.length === 0 ? (
            <div className="space-y-3 p-6">
              {[...Array(4)].map((_, i) => <div key={i} className="h-24 animate-pulse rounded-2xl bg-white/5" />)}
            </div>
          ) : pending.length === 0 ? (
            <div className="flex flex-1 flex-col items-center justify-center py-20 text-center">
              <div className={`mb-3 flex h-14 w-14 items-center justify-center rounded-full bg-white/5 ${t.accentText}`}>
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" className="h-7 w-7">
                  <path d="M5 13l4 4L19 7" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              </div>
              <p className="font-semibold text-white">Queue is clear</p>
              <p className={`mt-1 text-sm ${t.accentMuted}`}>No {t.label.toLowerCase()} requests pending.</p>
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto p-4 space-y-3">
              {pending.map((b, i) => {
                const isFirst = i === 0;
                return (
                  <div key={b.id} className={`relative overflow-hidden rounded-2xl ring-1 ${isFirst ? `ring-1 ${t.ring} bg-white/10 shadow-lg` : "bg-white/5 ring-white/8 hover:bg-white/8"} transition-all`}>
                    {isFirst && <div className={`absolute inset-y-0 left-0 w-1.5 rounded-l-2xl ${t.accent}`} />}
                    <div className="flex items-start gap-4 px-5 py-4 pl-6">
                      {/* Position */}
                      <div className={`mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-xl text-base font-black ${isFirst ? t.badge : t.badgeMuted}`}>
                        {i + 1}
                      </div>
                      {/* Info */}
                      <div className="min-w-0 flex-1">
                        <div className="flex flex-wrap items-center gap-2">
                          <span className="text-base font-bold text-white">{b.vessel.boatName}</span>
                          {b.vessel.yardNumber ? (
                            <span className={`rounded-full bg-white/10 px-2 py-0.5 text-xs font-semibold ${t.accentText}`}>
                              Yard #{b.vessel.yardNumber}
                            </span>
                          ) : null}
                          {b.stayingOnMooring ? (
                            <span className="rounded-full bg-sky-500/20 px-2 py-0.5 text-xs font-semibold text-sky-300 ring-1 ring-sky-400/30">
                              Mooring
                            </span>
                          ) : null}
                        </div>
                        <div className="mt-1.5 flex flex-wrap items-center gap-x-3 gap-y-0.5 text-sm">
                          {b.vessel.owner.username ? (
                            <span className="rounded-full bg-sky-500/15 px-2 py-0.5 text-xs font-bold text-sky-300">
                              @{b.vessel.owner.username}
                            </span>
                          ) : null}
                          <span className="font-medium text-white/80">{b.vessel.owner.name}</span>
                          {b.vessel.owner.phone ? (
                            <a href={`tel:${b.vessel.owner.phone}`}
                              className={`font-mono text-sm ${t.accentText} hover:text-white hover:underline`}>
                              {b.vessel.owner.phone}
                            </a>
                          ) : null}
                        </div>
                        <div className="mt-1 text-xs text-white/30">
                          Requested {b.requestedAt ? new Date(b.requestedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}
                        </div>
                      </div>
                      {/* Actions */}
                      <div className="flex shrink-0 flex-col gap-2">
                        <button
                          disabled={actionId === b.id}
                          onClick={() => markCompleted(b.id)}
                          className={`rounded-xl px-4 py-2 text-sm font-bold shadow transition disabled:opacity-50 ${t.completedBtn}`}
                        >
                          {actionId === b.id ? "…" : t.actionLabel}
                        </button>
                        <button
                          disabled={actionId === b.id}
                          onClick={() => cancelBooking(b.id)}
                          className="rounded-xl bg-red-900/40 px-4 py-2 text-xs font-semibold text-red-300 ring-1 ring-red-500/20 transition hover:bg-red-800/50 disabled:opacity-50"
                        >
                          Remove
                        </button>
                        <button
                          disabled={actionId === b.id}
                          onClick={() => toggleMooring(b.id, !b.stayingOnMooring)}
                          className={`rounded-xl px-4 py-1.5 text-xs font-semibold transition disabled:opacity-50 ${b.stayingOnMooring ? "bg-sky-500/20 text-sky-300 hover:bg-sky-500/30" : "bg-white/5 text-white/40 hover:text-white/70"}`}
                        >
                          {b.stayingOnMooring ? "Unset mooring" : "Mooring"}
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Completed column ── */}
        <div className="flex w-full flex-col overflow-hidden lg:w-80">
          <div className="flex items-center justify-between border-b border-white/10 px-6 py-3">
            <h2 className="text-xs font-bold uppercase tracking-widest text-white/40">
              Completed today ({completed.length})
            </h2>
          </div>
          {completed.length === 0 ? (
            <div className="flex flex-1 items-center justify-center py-12">
              <p className="text-sm text-white/25">None yet</p>
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto p-4 space-y-2">
              {completed.map((b) => (
                <div key={b.id} className="flex items-start gap-3 rounded-xl bg-white/4 px-4 py-3 opacity-70 hover:opacity-100 transition-opacity">
                  <span className="mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-white/10 text-xs text-white/50">✓</span>
                  <div className="min-w-0 flex-1 space-y-0.5">
                    <div className="flex flex-wrap items-center gap-1.5">
                      <span className="font-semibold text-white/80 text-sm">{b.vessel.boatName}</span>
                      {b.vessel.yardNumber ? <span className="text-xs text-white/30">#{b.vessel.yardNumber}</span> : null}
                    </div>
                    <div className="text-xs text-white/40">
                      {b.vessel.owner.name}
                      {b.completedAt ? <span> · {new Date(b.completedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}</span> : null}
                    </div>
                    {b.vessel.owner.phone ? (
                      <a href={`tel:${b.vessel.owner.phone}`} className="text-xs text-sky-400/70 hover:text-sky-300 hover:underline">
                        {b.vessel.owner.phone}
                      </a>
                    ) : null}
                    {b.stayingOnMooring ? (
                      <span className="inline-block rounded-full bg-sky-500/15 px-2 py-0.5 text-xs text-sky-400">Mooring</span>
                    ) : null}
                  </div>
                  {type === "LAUNCH" ? (
                    <button
                      disabled={actionId === b.id}
                      onClick={() => toggleMooring(b.id, !b.stayingOnMooring)}
                      className={`shrink-0 rounded-lg px-2 py-1 text-xs font-medium transition disabled:opacity-40 ${b.stayingOnMooring ? "bg-sky-500/20 text-sky-300 hover:bg-sky-500/30" : "bg-white/5 text-white/30 hover:text-white/60"}`}
                    >
                      {actionId === b.id ? "…" : b.stayingOnMooring ? "Unset" : "Mooring"}
                    </button>
                  ) : null}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

