"use client";

import * as React from "react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { getSocket } from "@/lib/socketClient";
import { triggerBoatAnimation } from "@/components/boat-animation";
import { playAdminAlert, playCustomerNotification } from "@/lib/queueSounds";
import type { QueueResponseAdminDTO, QueueResponseCustomerDTO } from "@/lib/apiTypes";

type QueueType = "LAUNCH" | "RETRIEVAL";

// ─── Launch Queue ─────────────────────────────────────────────────────────────

function LaunchQueue({ data, loading, error, isAdmin, actionPendingId, onMarkCompleted, onToggleMooring, onRefresh }: QueueProps) {
  const pending = (isAdmin ? (data as QueueResponseAdminDTO | null)?.pending : (data as QueueResponseCustomerDTO | null)?.pending) ?? [];
  const completed = (isAdmin ? (data as QueueResponseAdminDTO | null)?.completed : (data as QueueResponseCustomerDTO | null)?.completed) ?? [];

  return (
    <div className="min-h-screen bg-gradient-to-br from-emerald-950 via-teal-900 to-sky-900">
      {/* Hero */}
      <div className="relative overflow-hidden px-4 pb-8 pt-10">
        {/* Decorative wave */}
        <svg aria-hidden="true" className="absolute bottom-0 left-0 w-full text-emerald-800/40" viewBox="0 0 1200 80" preserveAspectRatio="none">
          <path d="M0 40 Q300 0 600 40 Q900 80 1200 40 L1200 80 L0 80Z" fill="currentColor" />
        </svg>
        <div className="relative mx-auto max-w-2xl">
          {/* Back nav */}
          <Link href="/queue" className="mb-6 inline-flex items-center gap-1.5 text-xs font-medium text-emerald-300/80 hover:text-white transition-colors">
