// ─── Shared types & controller ────────────────────────────────────────────────

type QueueData = QueueResponseAdminDTO | QueueResponseCustomerDTO | null;

interface QueueProps {
  data: QueueData;
  loading: boolean;
  error: string | null;
  isAdmin: boolean;
  actionPendingId: string | null;
  onMarkCompleted: (id: string) => void;
  onToggleMooring: (id: string, val: boolean) => void;
  onRefresh: () => void;
}

export function QueueClient({ type, isAdmin }: { type: QueueType; isAdmin: boolean }) {
  const [data, setData] = React.useState<QueueData>(null);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string | null>(null);
  const [actionPendingId, setActionPendingId] = React.useState<string | null>(null);

  async function load() {
    setError(null);
    setLoading(true);
    const res = await fetch(`/api/queues/${type}`, { cache: "no-store" });
    if (!res.ok) {
      const j = (await res.json().catch(() => null)) as { error?: string } | null;
      setError(j?.error ?? "Failed to load queue");
      setLoading(false);
      return;
    }
    setData(await res.json());
    setLoading(false);
  }

  async function handleMarkCompleted(id: string) {
    if (!isAdmin) return;
    setActionPendingId(id);
    try {
      await fetch(`/api/admin/bookings/${id}`, {
        method: "PATCH",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ action: "MARK_COMPLETED" }),
      });
      triggerBoatAnimation(type === "LAUNCH" ? "launch" : "retrieval");
      await load();
    } finally {
      setActionPendingId(null);
    }
  }

  async function handleToggleMooring(id: string, val: boolean) {
    if (!isAdmin) return;
    setActionPendingId(id);
    try {
      await fetch(`/api/admin/bookings/${id}`, {
        method: "PATCH",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ action: "SET_MOORING", stayingOnMooring: val }),
      });
      await load();
    } finally {
      setActionPendingId(null);
    }
  }

  React.useEffect(() => {
    load();
    let active = true;
    const interval = setInterval(() => { if (active) load(); }, 3 * 60 * 1000);
    (async () => {
      const socket = await getSocket();
      if (!active) return;
      socket.emit("queues:subscribe", {});
      const onUpdated = () => {
        load();
        if (isAdmin) playAdminAlert();
        else playCustomerNotification();
      };
      socket.on("queues:updated", onUpdated);
      return () => { socket.off("queues:updated", onUpdated); };
    })();
    return () => { active = false; clearInterval(interval); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [type]);

  const props: QueueProps = {
    data, loading, error, isAdmin, actionPendingId,
    onMarkCompleted: handleMarkCompleted,
    onToggleMooring: handleToggleMooring,
    onRefresh: load,
  };

  return type === "LAUNCH" ? <LaunchQueue {...props} /> : <RetrievalQueue {...props} />;
}

