// ── Main widget ────────────────────────────────────────────────────
export function ConditionsWidget() {
  const [homeData, setHomeData] = useState<Conditions | null>(null);
  const [homeTime, setHomeTime] = useState("");
  const [homeLoading, setHomeLoading] = useState(true);
  const [homeName, setHomeName] = useState("Your Location");
  const [homeTz, setHomeTz] = useState(Intl.DateTimeFormat().resolvedOptions().timeZone);

  const [query, setQuery] = useState("");
  const [suggestions, setSuggestions] = useState<GeoResult[]>([]);
  const [suggestionsOpen, setSuggestionsOpen] = useState(false);
  const [destLocation, setDestLocation] = useState<GeoResult | null>(null);
  const [destData, setDestData] = useState<Conditions | null>(null);
  const [destTime, setDestTime] = useState("");
  const [destLoading, setDestLoading] = useState(false);

  // Forecast selectors
  const [selDate, setSelDate] = useState(todayStr);
  const [selHour, setSelHour] = useState<number>(currentHour);
  const isForecastMode = selDate !== todayStr() || selHour !== currentHour();

  const inputRef = useRef<HTMLInputElement>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Fetch home conditions using browser geolocation
  useEffect(() => {
    const fetchConditions = async (lat: number, lon: number, tz: string) => {
      try {
        const res = await fetch(`/api/conditions?lat=${lat}&lon=${lon}&timezone=${encodeURIComponent(tz)}`);
        setHomeData(await res.json());
      } finally {
        setHomeLoading(false);
      }
    };

    if (!navigator.geolocation) {
      setHomeLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude, longitude } = pos.coords;
        const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
        setHomeTz(tz);
        // Try to resolve a friendly name via reverse geocoding
        try {
          const res = await fetch(`/api/geocode?lat=${latitude.toFixed(4)}&lon=${longitude.toFixed(4)}`);
          const data = await res.json();
          if (Array.isArray(data) && data[0]) {
            const g = data[0] as GeoResult;
            setHomeName(`${g.name}${g.admin1 ? `, ${g.admin1}` : ""}`);
            if (g.timezone) setHomeTz(g.timezone);
          }
        } catch { /* ignore — keep "Your Location" */ }
        await fetchConditions(latitude, longitude, tz);
      },
      () => {
        // Geolocation denied — show no data rather than wrong city
        setHomeLoading(false);
      },
      { timeout: 8000 },
    );
  }, []);

  // Clock tick
  useEffect(() => {
    const tick = () => {
      setHomeTime(localTime(homeTz));
      if (destLocation && !isForecastMode) setDestTime(localTime(destLocation.timezone));
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [homeTz, destLocation, isForecastMode]);

  // Debounced geocode search
  const handleQueryChange = (val: string) => {
    setQuery(val);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    if (val.trim().length < 2) { setSuggestions([]); setSuggestionsOpen(false); return; }
    debounceRef.current = setTimeout(async () => {
      const res = await fetch(`/api/geocode?q=${encodeURIComponent(val)}`);
      const data = await res.json();
      setSuggestions(Array.isArray(data) ? data : []);
      setSuggestionsOpen(true);
    }, 300);
  };

  const fetchDest = useCallback(async (loc: GeoResult, date: string, hour: number) => {
    setDestLoading(true);
    setDestData(null);
    const isToday = date === todayStr() && hour === currentHour();
    try {
      const params = new URLSearchParams({
        lat: String(loc.latitude),
        lon: String(loc.longitude),
        timezone: loc.timezone,
        ...(!isToday ? { date, hour: String(hour) } : {}),
      });
      const res = await fetch(`/api/conditions?${params}`);
      setDestData(await res.json());
    } finally {
      setDestLoading(false);
    }
  }, []);

  const selectDestination = useCallback((loc: GeoResult) => {
    setDestLocation(loc);
    setQuery(`${loc.name}, ${loc.admin1 ?? loc.country}`);
    setSuggestionsOpen(false);
    fetchDest(loc, selDate, selHour);
  }, [fetchDest, selDate, selHour]);

  const handleGetForecast = () => {
    if (destLocation) fetchDest(destLocation, selDate, selHour);
  };

  const forecastLabel = isForecastMode
    ? `${new Date(selDate + "T12:00:00").toLocaleDateString("en-CA", { weekday: "short", month: "short", day: "numeric" })} at ${fmtHour(selHour)}`
    : null;

  return (
    <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
      {/* ── Home Conditions ── */}
      <ConditionsPanel
        title="My Location"
        location={homeName}
        time={homeTime}
        data={homeData}
        loading={homeLoading}
        accent="sky"
      />

      {/* ── Destination Conditions ── */}
      <div className="relative overflow-hidden rounded-2xl border border-teal-200/60 bg-white/70 shadow-sm backdrop-blur-sm">
        {/* header */}
        <div className="flex items-center justify-between border-b border-teal-100/60 px-5 pt-4 pb-3">
          <div className="flex items-center gap-2">
            <AnchorIcon className="h-4 w-4 text-teal-600" />
            <span className="text-xs font-semibold uppercase tracking-widest text-teal-700">Destination Conditions</span>
          </div>
          {isForecastMode && (
            <span className="rounded-full bg-teal-100 px-2.5 py-0.5 text-[10px] font-semibold text-teal-700">Forecast</span>
          )}
        </div>

        <div className="space-y-2 px-4 pt-3 pb-2">
          {/* Location search */}
          <div className="relative">
            <div className="flex items-center gap-2 rounded-xl border border-teal-200 bg-white px-3 py-2 shadow-sm focus-within:ring-2 focus-within:ring-teal-400/50">
              <SearchIcon className="h-4 w-4 flex-shrink-0 text-teal-400" />
              <input
                ref={inputRef}
                type="text"
                value={query}
                onChange={(e) => handleQueryChange(e.target.value)}
                onFocus={() => suggestions.length > 0 && setSuggestionsOpen(true)}
                onBlur={() => setTimeout(() => setSuggestionsOpen(false), 150)}
                placeholder="Search a location…"
                className="w-full bg-transparent text-sm text-sky-900 placeholder-sky-400/60 outline-none"
              />
              {query && (
                <button
                  onClick={() => { setQuery(""); setSuggestions([]); setDestLocation(null); setDestData(null); }}
                  className="text-sky-400 hover:text-sky-600"
                >
                  <XIcon className="h-3.5 w-3.5" />
                </button>
              )}
            </div>
            {suggestionsOpen && suggestions.length > 0 && (
              <ul className="absolute left-0 right-0 top-full z-20 mt-1 overflow-hidden rounded-xl border border-teal-100 bg-white shadow-lg">
                {suggestions.map((s) => (
                  <li key={s.id}>
                    <button
                      onMouseDown={() => selectDestination(s)}
                      className="flex w-full items-center gap-2 px-3 py-2.5 text-left text-sm text-sky-900 hover:bg-teal-50"
                    >
                      <PinIcon className="h-3.5 w-3.5 flex-shrink-0 text-teal-500" />
                      <span className="font-medium">{s.name}</span>
                      <span className="text-xs text-sky-500">{[s.admin1, s.country].filter(Boolean).join(", ")}</span>
                    </button>
                  </li>
                ))}
              </ul>
            )}
          </div>

          {/* Date + Hour pickers */}
          <div className="flex gap-2">
            <div className="flex flex-1 items-center gap-1.5 rounded-xl border border-teal-200 bg-white px-3 py-2 shadow-sm focus-within:ring-2 focus-within:ring-teal-400/50">
              <CalendarIcon className="h-4 w-4 flex-shrink-0 text-teal-400" />
              <input
                type="date"
                value={selDate}
                min={todayStr()}
                max={maxDateStr()}
                onChange={(e) => setSelDate(e.target.value || todayStr())}
                className="w-full bg-transparent text-sm text-sky-900 outline-none"
              />
            </div>
            <div className="flex items-center gap-1.5 rounded-xl border border-teal-200 bg-white px-3 py-2 shadow-sm focus-within:ring-2 focus-within:ring-teal-400/50">

