                type="date"
                value={selDate}
                min={todayStr()}
                max={maxDateStr()}
                onChange={(e) => setSelDate(e.target.value || todayStr())}
                className="w-full bg-transparent text-sm text-sky-900 outline-none"
              />
            </div>
            <div className="flex items-center gap-1.5 rounded-xl border border-teal-200 bg-white px-3 py-2 shadow-sm focus-within:ring-2 focus-within:ring-teal-400/50">
              <ClockIcon className="h-4 w-4 flex-shrink-0 text-teal-400" />
              <select
                value={selHour}
                onChange={(e) => setSelHour(Number(e.target.value))}
                className="bg-transparent text-sm text-sky-900 outline-none"
              >
                {Array.from({ length: 24 }, (_, h) => (
                  <option key={h} value={h}>{fmtHour(h)}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Get forecast button — shown when pickers differ from "now" */}
          {isForecastMode && destLocation && (
            <button
              onClick={handleGetForecast}
              disabled={destLoading}
              className="flex w-full items-center justify-center gap-2 rounded-xl bg-teal-600 px-4 py-2 text-sm font-semibold text-white transition-colors hover:bg-teal-500 disabled:opacity-60"
            >
              {destLoading ? (
                <span className="animate-pulse">Fetching forecast…</span>
              ) : (
                <>
                  <SearchIcon className="h-4 w-4" />
                  Get forecast for {forecastLabel}
                </>
              )}
            </button>
          )}
        </div>

        {/* Results */}
        {destLocation ? (
          <div className="px-4 pb-4">
            <ConditionStats
              location={`${destLocation.name}, ${destLocation.admin1 ?? destLocation.country}`}
              time={isForecastMode ? forecastLabel ?? "" : destTime}
              data={destData}
              loading={destLoading}
              accent="teal"
              forecastLabel={forecastLabel}
            />
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center px-4 pb-8 pt-2 text-center">
            <CompassIcon className="h-10 w-10 text-teal-200" />
            <p className="mt-2 text-xs text-sky-500">Search a location to see conditions or forecast.</p>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Shared panel ───────────────────────────────────────────────────
function ConditionsPanel({
  title, location, time, data, loading, accent,
}: {
  title: string;
  location: string;
  time: string;
  data: Conditions | null;
  loading: boolean;
  accent: "sky" | "teal";
}) {
  const borderColor = accent === "sky" ? "border-sky-200/60" : "border-teal-200/60";
  const headerBorder = accent === "sky" ? "border-sky-100/60" : "border-teal-100/60";
  const iconColor = accent === "sky" ? "text-sky-600" : "text-teal-600";
  const labelColor = accent === "sky" ? "text-sky-700" : "text-teal-700";

  return (
    <div className={`overflow-hidden rounded-2xl border ${borderColor} bg-white/70 shadow-sm backdrop-blur-sm`}>
      <div className={`flex items-center gap-2 border-b ${headerBorder} px-5 pt-4 pb-3`}>
        <HomeIcon className={`h-4 w-4 ${iconColor}`} />
        <span className={`text-xs font-semibold uppercase tracking-widest ${labelColor}`}>{title}</span>
      </div>
      <div className="px-4 pb-4 pt-3">
        <ConditionStats location={location} time={time} data={data} loading={loading} accent={accent} />
      </div>
    </div>
  );
}

// ── Stat grid ──────────────────────────────────────────────────────
function ConditionStats({
  location, time, data, loading, accent, forecastLabel,
}: {
  location: string;
  time: string;
  data: Conditions | null;
  loading: boolean;
  accent: "sky" | "teal";
  forecastLabel?: string | null;
}) {
  const accentText = accent === "sky" ? "text-sky-600" : "text-teal-600";
  const accentBg = accent === "sky" ? "bg-sky-50" : "bg-teal-50";
  const accentBorder = accent === "sky" ? "border-sky-100" : "border-teal-100";

  return (
    <>
      <div className="mb-3 flex items-center justify-between gap-2">
        <span className={`truncate text-xs font-semibold ${accentText}`}>{location}</span>
        {forecastLabel
          ? <span className="shrink-0 text-xs text-sky-500">{forecastLabel}</span>
          : <span className="shrink-0 font-mono text-sm font-bold text-sky-900">{time || "—:—:—"}</span>
        }
      </div>

      {loading ? (
        <div className="grid grid-cols-2 gap-2">
          {[0, 1, 2, 3].map((i) => (
            <div key={i} className={`h-16 animate-pulse rounded-xl ${accentBg}`} />
          ))}
        </div>
      ) : data ? (
        <>
          <div className="grid grid-cols-2 gap-2">
            <StatCard
              icon={<ThermometerIcon className={`h-5 w-5 ${accentText}`} />}
              label="Temperature"
              value={data.temperature !== null ? `${data.temperature.toFixed(1)} °C` : "—"}
              bg={accentBg}
              border={accentBorder}
            />
            <StatCard
              icon={<WindIcon className={`h-5 w-5 ${accentText}`} />}
              label="Wind"
              value={data.windSpeed !== null ? `${data.windSpeed.toFixed(0)} km/h ${windCardinal(data.windDirection)}` : "—"}
              bg={accentBg}
              border={accentBorder}
            />
            <StatCard
              icon={<WaveIcon className={`h-5 w-5 ${accentText}`} />}
              label="Swell"
              value={data.waveHeight !== null
                ? `${data.waveHeight.toFixed(1)} m${data.wavePeriod !== null ? ` · ${data.wavePeriod.toFixed(0)}s` : ""}`
                : "—"}
              bg={accentBg}
              border={accentBorder}
            />
            <StatCard
              icon={<WeatherIcon code={data.weatherCode} className={`h-5 w-5 ${accentText}`} />}
              label="Sky"
              value={weatherLabel(data.weatherCode)}
              bg={accentBg}
              border={accentBorder}
            />
          </div>
          {(data.sunrise || data.sunset) && (
            <div className="mt-2 flex items-center gap-4 rounded-xl border border-sky-100 bg-sky-50 px-3 py-1.5 text-xs text-sky-600">
              {data.sunrise && <span>🌅 {fmtSunTime(data.sunrise)}</span>}
              {data.sunset && <span>🌇 {fmtSunTime(data.sunset)}</span>}
            </div>
          )}
          {data.tides && data.tides.length > 0 && (
            <div className={`mt-2 rounded-xl border ${accentBorder} ${accentBg} px-3 py-2`}>
              <div className={`mb-1.5 flex items-center gap-1.5 text-[10px] font-semibold uppercase tracking-wider ${accentText}`}>
                <TideIcon className="h-3.5 w-3.5" />
                Tides
              </div>
              <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                {data.tides.map((t, i) => (
                  <div key={i} className="flex items-center justify-between gap-2 text-xs">
                    <span className={`font-semibold ${t.type === "high" ? "text-blue-600" : "text-sky-400"}`}>
                      {t.type === "high" ? "▲ High" : "▼ Low"}
                    </span>
                    <span className="text-sky-900 font-bold">{t.height.toFixed(1)} m</span>
                    <span className="text-sky-500">{fmtSunTime(t.time)}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      ) : (
        <p className="py-4 text-center text-xs text-sky-400">No data available.</p>
      )}
    </>
  );
}

function StatCard({ icon, label, value, bg, border }: {
  icon: React.ReactNode;
  label: string;
  value: string;
  bg: string;
  border: string;
}) {
  return (
    <div className={`flex items-start gap-2.5 rounded-xl border ${border} ${bg} px-3 py-2.5`}>
      <div className="mt-0.5 flex-shrink-0">{icon}</div>
      <div className="min-w-0">
        <div className="text-[10px] font-semibold uppercase tracking-wider text-sky-500">{label}</div>
        <div className="mt-0.5 truncate text-sm font-bold text-sky-900">{value}</div>
      </div>
    </div>
  );
}

