import { redirect } from "next/navigation";
import { db } from "@/lib/db";
import { getCurrentUser } from "@/lib/currentUser";
import { startOfTodayLocal } from "@/lib/dates";
import { DashboardClient } from "@/app/dashboard/dashboard-client";

export default async function DashboardPage() {
  const user = await getCurrentUser();
  if (!user) redirect("/login");
  if (user.role === "ADMIN") redirect("/admin");

  const serviceDate = startOfTodayLocal();

  const [vessels, mooringRows] = await Promise.all([
    db.vessel.findMany({
      where: { userId: user.id },
      orderBy: [{ yardNumber: "asc" }, { boatName: "asc" }],
      select: {
        id: true,
        yardNumber: true,
        boatName: true,
        boatType: true,
        boatNumber: true,
        bookings: {
          where: { serviceDate },
          select: { id: true, type: true, status: true, requestedAt: true },
          orderBy: { requestedAt: "asc" },
        },
      },
    }),
    // Vessels the user left on the mooring from a previous day
    db.booking.findMany({
      where: { vessel: { userId: user.id }, type: "LAUNCH", status: "COMPLETED", stayingOnMooring: true },
      select: { vesselId: true },
    }),
  ]);

  const mooringVesselIds = new Set(mooringRows.map((r) => r.vesselId));

  const vesselsForClient = vessels.map((v) => ({
    ...v,
    canRetrieve:
      mooringVesselIds.has(v.id) ||
      v.bookings.some((b) => b.type === "LAUNCH" && b.status === "COMPLETED"),
    canStayOut:
      mooringVesselIds.has(v.id) ||
      v.bookings.some((b) => b.type === "LAUNCH" && (b.status === "COMPLETED" || b.status === "PENDING")),
    stayingOnMooring: mooringVesselIds.has(v.id),
    bookings: v.bookings
      .filter((b) => b.status === "PENDING")
      .map((b) => ({ ...b, requestedAt: b.requestedAt.toISOString() })),
  }));

  return <DashboardClient userName={user.name} userHandle={user.username ?? null} vessels={vesselsForClient} />;
}

