// ── Compact home-only banner for the homepage ───────────────────────
export function HomeConditions() {
  const [data, setData] = useState<Conditions | null>(null);
  const [time, setTime] = useState("");
  const [loading, setLoading] = useState(true);
  const [name, setName] = useState("Your Location");
  const [tz, setTz] = useState(Intl.DateTimeFormat().resolvedOptions().timeZone);

  useEffect(() => {
    if (!navigator.geolocation) { setLoading(false); return; }
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude, longitude } = pos.coords;
        const resolvedTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
        setTz(resolvedTz);
        try {
          const geo = await fetch(`/api/geocode?lat=${latitude.toFixed(4)}&lon=${longitude.toFixed(4)}`);
          const geoData = await geo.json();
          if (Array.isArray(geoData) && geoData[0]) {
            const g = geoData[0] as GeoResult;
            setName(`${g.name}${g.admin1 ? `, ${g.admin1}` : ""}`);
            if (g.timezone) setTz(g.timezone);
          }
        } catch { /* keep "Your Location" */ }
        try {
          const res = await fetch(`/api/conditions?lat=${latitude}&lon=${longitude}&timezone=${encodeURIComponent(resolvedTz)}`);
          setData(await res.json());
        } finally {
          setLoading(false);
        }
      },
      () => setLoading(false),
      { timeout: 8000 },
    );
  }, []);

  useEffect(() => {
    const tick = () => setTime(localTime(tz));
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [tz]);

  return (
    <div className="flex flex-wrap items-center gap-x-4 gap-y-2 rounded-2xl border border-sky-200/60 bg-white/70 px-4 py-3 shadow-sm backdrop-blur-sm">
      {/* Location + clock */}
      <div className="flex items-center gap-2 min-w-0">
        <HomeIcon className="h-4 w-4 flex-shrink-0 text-sky-500" />
        <span className="text-xs font-semibold text-sky-700">{name}</span>
        <span className="font-mono text-sm font-bold text-sky-900">{time || "—:—:—"}</span>
      </div>

      <div className="hidden sm:block h-4 w-px bg-sky-200" />

      {loading ? (
        <div className="flex gap-3">
          {[0, 1, 2, 3].map((i) => <div key={i} className="h-5 w-20 animate-pulse rounded-lg bg-sky-100" />)}
        </div>
      ) : data ? (
        <div className="flex flex-wrap items-center gap-x-4 gap-y-1.5">
          {/* Temp */}
          <div className="flex items-center gap-1.5">
            <ThermometerIcon className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">
              {data.temperature !== null ? `${data.temperature.toFixed(1)} °C` : "—"}
            </span>
          </div>
          {/* Wind */}
          <div className="flex items-center gap-1.5">
            <WindIcon className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">
              {data.windSpeed !== null ? `${data.windSpeed.toFixed(0)} km/h ${windCardinal(data.windDirection)}` : "—"}
            </span>
          </div>
          {/* Swell */}
          <div className="flex items-center gap-1.5">
            <WaveIcon className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">
              {data.waveHeight !== null
                ? `${data.waveHeight.toFixed(1)} m${data.wavePeriod !== null ? ` · ${data.wavePeriod.toFixed(0)}s` : ""}`
                : "—"}
            </span>
          </div>
          {/* Sky */}
          <div className="flex items-center gap-1.5">
            <WeatherIcon code={data.weatherCode} className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">{weatherLabel(data.weatherCode)}</span>
          </div>
          {/* Next tide */}
          {data.tides && data.tides.length > 0 && (
            <div className="flex items-center gap-1.5">
              <TideIcon className="h-4 w-4 text-sky-500" />
              <span className="text-sm font-bold text-sky-900">
                {data.tides[0].type === "high" ? "▲" : "▼"} {data.tides[0].height.toFixed(1)} m · {fmtSunTime(data.tides[0].time)}
              </span>
            </div>
          )}
        </div>
      ) : null}
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";

// ── Types ──────────────────────────────────────────────────────────
interface TideEvent {
  time: string;
  height: number;
  type: "high" | "low";
}

interface Conditions {
  temperature: number | null;
  windSpeed: number | null;
  windDirection: number | null;
  weatherCode: number | null;
  waveHeight: number | null;
  wavePeriod: number | null;
  sunrise?: string | null;
  sunset?: string | null;
  tides?: TideEvent[] | null;
  isForecast?: boolean;
}

function todayStr(): string {
  return new Date().toISOString().slice(0, 10);
}
function currentHour(): number {
  return new Date().getHours();
}
function maxDateStr(): string {
  const d = new Date();
  d.setDate(d.getDate() + 15);
  return d.toISOString().slice(0, 10);
}
function fmtHour(h: number): string {
  const suffix = h < 12 ? "AM" : "PM";
  const h12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
  return `${String(h12).padStart(2, "0")}:00 ${suffix}`;
}
function fmtSunTime(iso: string | null | undefined): string {
  if (!iso) return "";
  try { return new Date(iso).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }); }
  catch { return ""; }
}

interface GeoResult {
  id: number;
  name: string;
  country: string;
  admin1?: string;
  latitude: number;
  longitude: number;
  timezone: string;
}

// ── WMO weather code helpers ───────────────────────────────────────
function weatherLabel(code: number | null): string {
  if (code === null) return "—";
  if (code === 0) return "Clear sky";
  if (code <= 3) return ["", "Mainly clear", "Partly cloudy", "Overcast"][code] ?? "—";
  if (code <= 48) return "Fog";
  if (code <= 55) return "Drizzle";
  if (code <= 65) return "Rain";
  if (code <= 77) return "Snow";
  if (code <= 82) return "Showers";
  if (code <= 99) return "Thunderstorm";
  return "—";
}

function WeatherIcon({ code, className = "h-5 w-5" }: { code: number | null; className?: string }) {
  if (code === null) return <CloudIcon className={className} />;
  if (code === 0) return <SunIcon className={className} />;
  if (code <= 3) return <CloudSunIcon className={className} />;
  if (code <= 48) return <FogIcon className={className} />;
  if (code <= 77) return <RainIcon className={className} />;
  if (code <= 82) return <RainIcon className={className} />;
  return <ThunderIcon className={className} />;
}

function windCardinal(deg: number | null): string {
  if (deg === null) return "—";
  const dirs = ["N", "NE", "E", "SE", "S", "SW", "W", "NW"];
  return dirs[Math.round(deg / 45) % 8];
}

function localTime(tz: string): string {
  return new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  }).format(new Date());
}

// ── Pwllheli hardcoded location ─────────────────────────────────────
const PWLLHELI = { lat: 52.9263, lon: -4.4138, timezone: "Europe/London", name: "Pwllheli" };

// ── Main widget ────────────────────────────────────────────────────
export function ConditionsWidget() {
  const [data, setData] = useState<Conditions | null>(null);
  const [loading, setLoading] = useState(true);
  const [time, setTime] = useState("");

  useEffect(() => {
    const fetch_ = async () => {
      try {
        const res = await fetch(
          `/api/conditions?lat=${PWLLHELI.lat}&lon=${PWLLHELI.lon}&timezone=${encodeURIComponent(PWLLHELI.timezone)}`
        );
        setData(await res.json());
      } finally {
        setLoading(false);
      }
    };
    fetch_();
  }, []);

  useEffect(() => {
    const tick = () => setTime(localTime(PWLLHELI.timezone));
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, []);

  return (
    <ConditionsPanel
      title="Destination Conditions"
      location={PWLLHELI.name}
      time={time}
      data={data}
      loading={loading}
      accent="teal"
    />
  );
}

// ── Unused ── (search-based destination widget, replaced by Pwllheli hardcode)
// eslint-disable-next-line @typescript-eslint/no-unused-vars
function _UnusedDestWidget() {
  const [query, setQuery] = useState("");
  const [suggestions, setSuggestions] = useState<GeoResult[]>([]);
  const [suggestionsOpen, setSuggestionsOpen] = useState(false);
  const [destLocation, setDestLocation] = useState<GeoResult | null>(null);
  const [destData, setDestData] = useState<Conditions | null>(null);
  const [destTime, setDestTime] = useState("");
  const [destLoading, setDestLoading] = useState(false);

  const [selDate, setSelDate] = useState(todayStr);
  const [selHour, setSelHour] = useState<number>(currentHour);
  const isForecastMode = selDate !== todayStr() || selHour !== currentHour();

  const inputRef = useRef<HTMLInputElement>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const tick = () => {
      if (destLocation && !isForecastMode) setDestTime(localTime(destLocation.timezone));
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [destLocation, isForecastMode]);

  const handleQueryChange = (val: string) => {
    setQuery(val);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    if (val.trim().length < 2) { setSuggestions([]); setSuggestionsOpen(false); return; }
    debounceRef.current = setTimeout(async () => {
      const res = await fetch(`/api/geocode?q=${encodeURIComponent(val)}`);
      const data = await res.json();
      setSuggestions(Array.isArray(data) ? data : []);
      setSuggestionsOpen(true);
    }, 300);
  };

  const fetchDest = useCallback(async (loc: GeoResult, date: string, hour: number) => {
    setDestLoading(true);
    setDestData(null);
    const isToday = date === todayStr() && hour === currentHour();
    try {
      const params = new URLSearchParams({
        lat: String(loc.latitude),
        lon: String(loc.longitude),
        timezone: loc.timezone,
        ...(!isToday ? { date, hour: String(hour) } : {}),
      });
      const res = await fetch(`/api/conditions?${params}`);
      setDestData(await res.json());
    } finally {
      setDestLoading(false);
    }
  }, []);

  const selectDestination = useCallback((loc: GeoResult) => {
    setDestLocation(loc);
    setQuery(`${loc.name}, ${loc.admin1 ?? loc.country}`);
    setSuggestionsOpen(false);
    fetchDest(loc, selDate, selHour);
  }, [fetchDest, selDate, selHour]);

  const handleGetForecast = () => {
    if (destLocation) fetchDest(destLocation, selDate, selHour);
  };

  const forecastLabel = isForecastMode
    ? `${new Date(selDate + "T12:00:00").toLocaleDateString("en-CA", { weekday: "short", month: "short", day: "numeric" })} at ${fmtHour(selHour)}`
    : null;

  return (
    <div className="relative overflow-hidden rounded-2xl border border-teal-200/60 bg-white/70 shadow-sm backdrop-blur-sm">
      <div className="flex items-center justify-between border-b border-teal-100/60 px-5 pt-4 pb-3">
        <div className="flex items-center gap-2">
          <AnchorIcon className="h-4 w-4 text-teal-600" />
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-700">Destination Conditions</span>
        </div>
        {isForecastMode && (
          <span className="rounded-full bg-teal-100 px-2.5 py-0.5 text-[10px] font-semibold text-teal-700">Forecast</span>
        )}
      </div>

      <div className="space-y-2 px-4 pt-3 pb-2">
        <div className="relative">
          <div className="flex items-center gap-2 rounded-xl border border-teal-200 bg-white px-3 py-2 shadow-sm focus-within:ring-2 focus-within:ring-teal-400/50">
            <SearchIcon className="h-4 w-4 flex-shrink-0 text-teal-400" />
            <input
              ref={inputRef}
              type="text"
              value={query}
              onChange={(e) => handleQueryChange(e.target.value)}
              onFocus={() => suggestions.length > 0 && setSuggestionsOpen(true)}
              onBlur={() => setTimeout(() => setSuggestionsOpen(false), 150)}
              placeholder="Search a location…"
              className="w-full bg-transparent text-sm text-sky-900 placeholder-sky-400/60 outline-none"
            />
            {query && (
              <button
                onClick={() => { setQuery(""); setSuggestions([]); setDestLocation(null); setDestData(null); }}
                className="text-sky-400 hover:text-sky-600"
              >
                <XIcon className="h-3.5 w-3.5" />
              </button>
            )}
          </div>
          {suggestionsOpen && suggestions.length > 0 && (
            <ul className="absolute left-0 right-0 top-full z-20 mt-1 overflow-hidden rounded-xl border border-teal-100 bg-white shadow-lg">
              {suggestions.map((s) => (
                <li key={s.id}>
                  <button
                    onMouseDown={() => selectDestination(s)}
                    className="flex w-full items-center gap-2 px-3 py-2.5 text-left text-sm text-sky-900 hover:bg-teal-50"
                  >
                    <PinIcon className="h-3.5 w-3.5 flex-shrink-0 text-teal-500" />
                    <span className="font-medium">{s.name}</span>
                    <span className="text-xs text-sky-500">{[s.admin1, s.country].filter(Boolean).join(", ")}</span>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>

        <div className="flex gap-2">
          <div className="flex flex-1 items-center gap-1.5 rounded-xl border border-teal-200 bg-white px-3 py-2 shadow-sm focus-within:ring-2 focus-within:ring-teal-400/50">
            <CalendarIcon className="h-4 w-4 flex-shrink-0 text-teal-400" />
            <input
              type="date"
              value={selDate}
              min={todayStr()}
              max={maxDateStr()}
              onChange={(e) => setSelDate(e.target.value || todayStr())}
              className="w-full bg-transparent text-sm text-sky-900 outline-none"
            />
          </div>
          <div className="flex items-center gap-1.5 rounded-xl border border-teal-200 bg-white px-3 py-2 shadow-sm focus-within:ring-2 focus-within:ring-teal-400/50">
              <ClockIcon className="h-4 w-4 flex-shrink-0 text-teal-400" />
              <select
                value={selHour}
                onChange={(e) => setSelHour(Number(e.target.value))}
                className="bg-transparent text-sm text-sky-900 outline-none"
              >
                {Array.from({ length: 24 }, (_, h) => (
                  <option key={h} value={h}>{fmtHour(h)}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Get forecast button — shown when pickers differ from "now" */}
          {isForecastMode && destLocation && (
            <button
              onClick={handleGetForecast}
              disabled={destLoading}
              className="flex w-full items-center justify-center gap-2 rounded-xl bg-teal-600 px-4 py-2 text-sm font-semibold text-white transition-colors hover:bg-teal-500 disabled:opacity-60"
            >
              {destLoading ? (
                <span className="animate-pulse">Fetching forecast…</span>
              ) : (
                <>
                  <SearchIcon className="h-4 w-4" />
                  Get forecast for {forecastLabel}
                </>
              )}
            </button>
          )}
        </div>

        {/* Results */}
        {destLocation ? (
          <div className="px-4 pb-4">
            <ConditionStats
              location={`${destLocation.name}, ${destLocation.admin1 ?? destLocation.country}`}
              time={isForecastMode ? forecastLabel ?? "" : destTime}
              data={destData}
              loading={destLoading}
              accent="teal"
              forecastLabel={forecastLabel}
            />
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center px-4 pb-8 pt-2 text-center">
            <CompassIcon className="h-10 w-10 text-teal-200" />
            <p className="mt-2 text-xs text-sky-500">Search a location to see conditions or forecast.</p>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Shared panel ───────────────────────────────────────────────────
function ConditionsPanel({
  title, location, time, data, loading, accent,
}: {
  title: string;
  location: string;
  time: string;
  data: Conditions | null;
  loading: boolean;
  accent: "sky" | "teal";
}) {
  const borderColor = accent === "sky" ? "border-sky-200/60" : "border-teal-200/60";
  const headerBorder = accent === "sky" ? "border-sky-100/60" : "border-teal-100/60";
  const iconColor = accent === "sky" ? "text-sky-600" : "text-teal-600";
  const labelColor = accent === "sky" ? "text-sky-700" : "text-teal-700";

  return (
    <div className={`overflow-hidden rounded-2xl border ${borderColor} bg-white/70 shadow-sm backdrop-blur-sm`}>
      <div className={`flex items-center gap-2 border-b ${headerBorder} px-5 pt-4 pb-3`}>
        <HomeIcon className={`h-4 w-4 ${iconColor}`} />
        <span className={`text-xs font-semibold uppercase tracking-widest ${labelColor}`}>{title}</span>
      </div>
      <div className="px-4 pb-4 pt-3">
        <ConditionStats location={location} time={time} data={data} loading={loading} accent={accent} />
      </div>
    </div>
  );
}

// ── Stat grid ──────────────────────────────────────────────────────
function ConditionStats({
  location, time, data, loading, accent, forecastLabel,
}: {
  location: string;
  time: string;
  data: Conditions | null;
  loading: boolean;
  accent: "sky" | "teal";
  forecastLabel?: string | null;
}) {
  const accentText = accent === "sky" ? "text-sky-600" : "text-teal-600";
  const accentBg = accent === "sky" ? "bg-sky-50" : "bg-teal-50";
  const accentBorder = accent === "sky" ? "border-sky-100" : "border-teal-100";

  return (
    <>
      <div className="mb-3 flex items-center justify-between gap-2">
        <span className={`truncate text-xs font-semibold ${accentText}`}>{location}</span>
        {forecastLabel
          ? <span className="shrink-0 text-xs text-sky-500">{forecastLabel}</span>
          : <span className="shrink-0 font-mono text-sm font-bold text-sky-900">{time || "—:—:—"}</span>
        }
      </div>

      {loading ? (
        <div className="grid grid-cols-2 gap-2">
          {[0, 1, 2, 3].map((i) => (
            <div key={i} className={`h-16 animate-pulse rounded-xl ${accentBg}`} />
          ))}
        </div>
      ) : data ? (
        <>
          <div className="grid grid-cols-2 gap-2">
            <StatCard
              icon={<ThermometerIcon className={`h-5 w-5 ${accentText}`} />}
              label="Temperature"
              value={data.temperature !== null ? `${data.temperature.toFixed(1)} °C` : "—"}
              bg={accentBg}
              border={accentBorder}
            />
            <StatCard
              icon={<WindIcon className={`h-5 w-5 ${accentText}`} />}
              label="Wind"
              value={data.windSpeed !== null ? `${data.windSpeed.toFixed(0)} km/h ${windCardinal(data.windDirection)}` : "—"}
              bg={accentBg}
              border={accentBorder}
            />
            <StatCard
              icon={<WaveIcon className={`h-5 w-5 ${accentText}`} />}
              label="Swell"
              value={data.waveHeight !== null
                ? `${data.waveHeight.toFixed(1)} m${data.wavePeriod !== null ? ` · ${data.wavePeriod.toFixed(0)}s` : ""}`
                : "—"}
              bg={accentBg}
              border={accentBorder}
            />
            <StatCard
              icon={<WeatherIcon code={data.weatherCode} className={`h-5 w-5 ${accentText}`} />}
              label="Sky"
              value={weatherLabel(data.weatherCode)}
              bg={accentBg}
              border={accentBorder}
            />
          </div>
          {(data.sunrise || data.sunset) && (
            <div className="mt-2 flex items-center gap-4 rounded-xl border border-sky-100 bg-sky-50 px-3 py-1.5 text-xs text-sky-600">
              {data.sunrise && <span>🌅 {fmtSunTime(data.sunrise)}</span>}
              {data.sunset && <span>🌇 {fmtSunTime(data.sunset)}</span>}
            </div>
          )}
          {data.tides && data.tides.length > 0 && (
            <div className={`mt-2 rounded-xl border ${accentBorder} ${accentBg} px-3 py-2`}>
              <div className={`mb-1.5 flex items-center gap-1.5 text-[10px] font-semibold uppercase tracking-wider ${accentText}`}>
                <TideIcon className="h-3.5 w-3.5" />
                Tides
              </div>
              <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                {data.tides.map((t, i) => (
                  <div key={i} className="flex items-center justify-between gap-2 text-xs">
                    <span className={`font-semibold ${t.type === "high" ? "text-blue-600" : "text-sky-400"}`}>
                      {t.type === "high" ? "▲ High" : "▼ Low"}
                    </span>
                    <span className="text-sky-900 font-bold">{t.height.toFixed(1)} m</span>
                    <span className="text-sky-500">{fmtSunTime(t.time)}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      ) : (
        <p className="py-4 text-center text-xs text-sky-400">No data available.</p>
      )}
    </>
  );
}

function StatCard({ icon, label, value, bg, border }: {
  icon: React.ReactNode;
  label: string;
  value: string;
  bg: string;
  border: string;
}) {
  return (
    <div className={`flex items-start gap-2.5 rounded-xl border ${border} ${bg} px-3 py-2.5`}>
      <div className="mt-0.5 flex-shrink-0">{icon}</div>
      <div className="min-w-0">
        <div className="text-[10px] font-semibold uppercase tracking-wider text-sky-500">{label}</div>
        <div className="mt-0.5 truncate text-sm font-bold text-sky-900">{value}</div>
      </div>
    </div>
  );
}

