// ── Compact home-only banner for the homepage ───────────────────────
export function HomeConditions() {
  const [data, setData] = useState<Conditions | null>(null);
  const [time, setTime] = useState("");
  const [loading, setLoading] = useState(true);
  const [name, setName] = useState("Your Location");
  const [tz, setTz] = useState(Intl.DateTimeFormat().resolvedOptions().timeZone);

  useEffect(() => {
    if (!navigator.geolocation) { setLoading(false); return; }
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude, longitude } = pos.coords;
        const resolvedTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
        setTz(resolvedTz);
        try {
          const geo = await fetch(`/api/geocode?lat=${latitude.toFixed(4)}&lon=${longitude.toFixed(4)}`);
          const geoData = await geo.json();
          if (Array.isArray(geoData) && geoData[0]) {
            const g = geoData[0] as GeoResult;
            setName(`${g.name}${g.admin1 ? `, ${g.admin1}` : ""}`);
            if (g.timezone) setTz(g.timezone);
          }
        } catch { /* keep "Your Location" */ }
        try {
          const res = await fetch(`/api/conditions?lat=${latitude}&lon=${longitude}&timezone=${encodeURIComponent(resolvedTz)}`);
          setData(await res.json());
        } finally {
          setLoading(false);
        }
      },
      () => setLoading(false),
      { timeout: 8000 },
    );
  }, []);

  useEffect(() => {
    const tick = () => setTime(localTime(tz));
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [tz]);

  return (
    <div className="flex flex-wrap items-center gap-x-4 gap-y-2 rounded-2xl border border-sky-200/60 bg-white/70 px-4 py-3 shadow-sm backdrop-blur-sm">
      {/* Location + clock */}
      <div className="flex items-center gap-2 min-w-0">
        <HomeIcon className="h-4 w-4 flex-shrink-0 text-sky-500" />
        <span className="text-xs font-semibold text-sky-700">{name}</span>
        <span className="font-mono text-sm font-bold text-sky-900">{time || "—:—:—"}</span>
      </div>

      <div className="hidden sm:block h-4 w-px bg-sky-200" />

      {loading ? (
        <div className="flex gap-3">
          {[0, 1, 2, 3].map((i) => <div key={i} className="h-5 w-20 animate-pulse rounded-lg bg-sky-100" />)}
        </div>
      ) : data ? (
        <div className="flex flex-wrap items-center gap-x-4 gap-y-1.5">
          {/* Temp */}
          <div className="flex items-center gap-1.5">
            <ThermometerIcon className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">
              {data.temperature !== null ? `${data.temperature.toFixed(1)} °C` : "—"}
            </span>
          </div>
          {/* Wind */}
          <div className="flex items-center gap-1.5">
            <WindIcon className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">
              {data.windSpeed !== null ? `${data.windSpeed.toFixed(0)} km/h ${windCardinal(data.windDirection)}` : "—"}
            </span>
          </div>
          {/* Swell */}
          <div className="flex items-center gap-1.5">
            <WaveIcon className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">
              {data.waveHeight !== null
                ? `${data.waveHeight.toFixed(1)} m${data.wavePeriod !== null ? ` · ${data.wavePeriod.toFixed(0)}s` : ""}`
                : "—"}
            </span>
          </div>
          {/* Sky */}
          <div className="flex items-center gap-1.5">
            <WeatherIcon code={data.weatherCode} className="h-4 w-4 text-sky-500" />
            <span className="text-sm font-bold text-sky-900">{weatherLabel(data.weatherCode)}</span>
          </div>
          {/* Next tide */}
          {data.tides && data.tides.length > 0 && (
            <div className="flex items-center gap-1.5">
              <TideIcon className="h-4 w-4 text-sky-500" />
              <span className="text-sm font-bold text-sky-900">
                {data.tides[0].type === "high" ? "▲" : "▼"} {data.tides[0].height.toFixed(1)} m · {fmtSunTime(data.tides[0].time)}
              </span>
            </div>
          )}
        </div>
      ) : null}
    </div>
  );
}
